//+------------------------------------------------------------------+
//| EA_01_LiquiditySweep_FVG.mq5                                     |
//| Strategy: Liquidity Sweep + Fair Value Gap Entry                  |
//| Assets: XAUUSD, NAS100, EUR/USD - NY Session Scalping            |
//| Author: Jose - Prop Firm Challenge EA Suite                       |
//+------------------------------------------------------------------+
#property copyright "Jose - Quant Trading"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Input Parameters: Strategy
input group "=== STRATEGY PARAMETERS ==="
input int      InpLookbackBars     = 50;       // Bars to identify session highs/lows
input int      InpSweepMinPips     = 10;       // Minimum sweep beyond level (points)
input int      InpSweepMaxPips     = 80;       // Maximum sweep beyond level (points)
input int      InpFVG_MinSize      = 5;        // Minimum FVG size (points)
input int      InpFVG_MaxAge       = 10;       // Max bars old for valid FVG
input bool     InpRequireDisplacement = true;  // Require displacement candle after sweep
input int      InpDisplacementMinPips = 15;    // Min displacement candle body (points)

//--- Input Parameters: Session Filter
input group "=== SESSION FILTER (ET/NY Time) ==="
input int      InpSessionStartHour = 8;        // NY Session Start Hour (ET)
input int      InpSessionStartMin  = 30;       // NY Session Start Minute
input int      InpSessionEndHour   = 11;       // NY Session End Hour (ET)
input int      InpSessionEndMin    = 0;         // NY Session End Minute
input int      InpBrokerGMTOffset  = 2;        // Broker GMT Offset (e.g., 2 for GMT+2)

//--- Input Parameters: Risk Management
input group "=== RISK MANAGEMENT ==="
input double   InpRiskPercent      = 0.5;      // Risk per trade (% of balance)
input double   InpRR_Ratio         = 2.0;      // Risk:Reward ratio (1:X)
input int      InpMaxTradesPerDay  = 2;        // Max trades per day (Rule of Two Bullets)
input int      InpMaxConsecLosses  = 3;        // Max consecutive losses before pause
input double   InpDailyLossLimit   = 4.0;      // Daily loss limit (% of balance) - 80% of 5%
input double   InpMaxDrawdownPct   = 8.0;      // Max total drawdown (% of initial) - 80% of 10%
input int      InpMinTradeDuration = 90;       // Min trade duration seconds (Funding Pips)

//--- Input Parameters: Execution
input group "=== EXECUTION ==="
input int      InpMaxSpread        = 40;       // Max allowed spread (points)
input int      InpSlippage         = 10;       // Max slippage (points)
input int      InpMagicNumber      = 100100;   // Magic Number
input string   InpTradeComment     = "LS_FVG"; // Trade Comment

//--- Input Parameters: Report
input group "=== REPORT ==="
input bool     InpGenerateCSV      = true;     // Generate CSV report on deinit
input string   InpCSVFilename      = "EA01_LiquiditySweep_FVG_Report.csv"; // CSV filename

//--- Global Variables
CTrade         trade;
CPositionInfo  posInfo;

struct TradeRecord {
   int      ticket;
   datetime openTime;
   datetime closeTime;
   string   direction;
   double   entryPrice;
   double   exitPrice;
   double   sl;
   double   tp;
   double   lots;
   double   pnl;
   double   pnlPips;
   int      durationSec;
   string   sweepType;    // "Asian_High", "Asian_Low", "London_High", "London_Low", "PrevDay_High", "PrevDay_Low"
   double   fvgSize;
   double   displacement;
   double   balanceAfter;
};

TradeRecord    tradeLog[];
int            totalTrades;
int            dailyTrades;
int            consecLosses;
double         dailyPnL;
double         initialBalance;
double         peakBalance;
double         maxDrawdown;
datetime       lastTradeDay;
int            wins, losses;

// Session level tracking
double         asianHigh, asianLow;
double         londonHigh, londonLow;
double         prevDayHigh, prevDayLow;
bool           levelsCalculated;
datetime       lastLevelCalcDay;

// FVG tracking
struct FVGZone {
   double   top;
   double   bottom;
   datetime time;
   int      barIndex;
   bool     isBullish;
   bool     used;
};

FVGZone        fvgZones[];
int            fvgCount;

//+------------------------------------------------------------------+
//| Expert initialization function                                     |
//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   initialBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   peakBalance    = initialBalance;
   maxDrawdown    = 0;
   totalTrades    = 0;
   dailyTrades    = 0;
   consecLosses   = 0;
   dailyPnL       = 0;
   wins           = 0;
   losses         = 0;
   lastTradeDay   = 0;
   levelsCalculated = false;
   lastLevelCalcDay = 0;
   fvgCount       = 0;

   ArrayResize(tradeLog, 0);
   ArrayResize(fvgZones, 0);

   Print("EA01 LiquiditySweep+FVG initialized. Balance: ", initialBalance);
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                   |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(InpGenerateCSV && ArraySize(tradeLog) > 0)
      GenerateCSVReport();

   Print("EA01 Final Stats | Trades: ", totalTrades, " | Wins: ", wins, 
         " | Losses: ", losses, " | MaxDD: ", DoubleToString(maxDrawdown, 2), "%");
}

//+------------------------------------------------------------------+
//| Expert tick function                                               |
//+------------------------------------------------------------------+
void OnTick()
{
   // Only process on new bar
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   // Reset daily counters
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year) + "." + 
                                  IntegerToString(dt.mon) + "." + 
                                  IntegerToString(dt.day));
   if(today != lastTradeDay)
   {
      dailyTrades = 0;
      dailyPnL    = 0;
      lastTradeDay = today;
      levelsCalculated = false;
   }

   // Update drawdown tracking
   UpdateDrawdown();

   // Check risk limits
   if(!CheckRiskLimits()) return;

   // Manage existing positions (min duration, trailing)
   ManagePositions();

   // Calculate session levels
   CalculateSessionLevels();

   // Check if we're in the trading session
   if(!IsInSession()) return;

   // Check spread
   double spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > InpMaxSpread) return;

   // Skip if we already have a position
   if(HasOpenPosition()) return;

   // Scan for FVGs
   ScanForFVGs();

   // Look for liquidity sweep + FVG entry
   CheckForSweepEntry();
}

//+------------------------------------------------------------------+
//| Calculate session highs/lows for sweep detection                  |
//+------------------------------------------------------------------+
void CalculateSessionLevels()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year) + "." + 
                                  IntegerToString(dt.mon) + "." + 
                                  IntegerToString(dt.day));

   if(lastLevelCalcDay == today && levelsCalculated) return;

   // Convert broker time to ET: ET = BrokerTime - BrokerGMTOffset - 5 (or -4 DST)
   // For simplicity, we use bar scanning approach

   int totalBars = iBars(_Symbol, PERIOD_M5);
   if(totalBars < 300) return;

   // Previous day High/Low
   prevDayHigh = -DBL_MAX;
   prevDayLow  = DBL_MAX;

   // Scan backwards to find previous day's range
   MqlDateTime barDT;
   datetime prevDay = today - 86400;
   // Skip weekends
   TimeToStruct(prevDay, barDT);
   if(barDT.day_of_week == 0) prevDay -= 2 * 86400;
   if(barDT.day_of_week == 6) prevDay -= 86400;

   for(int i = 1; i < 300; i++)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime bdt;
      TimeToStruct(barTime, bdt);
      datetime barDay = StringToTime(IntegerToString(bdt.year) + "." + 
                                      IntegerToString(bdt.mon) + "." + 
                                      IntegerToString(bdt.day));

      if(barDay == prevDay || (barDay < today && barDay >= today - 3*86400))
      {
         double h = iHigh(_Symbol, PERIOD_M5, i);
         double l = iLow(_Symbol, PERIOD_M5, i);
         if(h > prevDayHigh) prevDayHigh = h;
         if(l < prevDayLow)  prevDayLow  = l;
      }
   }

   // Asian session (roughly 19:00-02:00 ET = 00:00-07:00 broker GMT+2)
   asianHigh = -DBL_MAX;
   asianLow  = DBL_MAX;

   int asianStartBroker = (19 + InpBrokerGMTOffset + 5) % 24; // ET to broker
   int asianEndBroker   = (2 + InpBrokerGMTOffset + 5) % 24;

   for(int i = 1; i < 200; i++)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime bdt;
      TimeToStruct(barTime, bdt);
      datetime barDay = StringToTime(IntegerToString(bdt.year) + "." + 
                                      IntegerToString(bdt.mon) + "." + 
                                      IntegerToString(bdt.day));

      if(barDay != today && barDay != today - 86400) continue;

      int barHour = bdt.hour;
      bool isAsian = false;

      if(asianStartBroker > asianEndBroker) // Crosses midnight
         isAsian = (barHour >= asianStartBroker || barHour < asianEndBroker);
      else
         isAsian = (barHour >= asianStartBroker && barHour < asianEndBroker);

      if(isAsian && barDay >= today - 86400)
      {
         double h = iHigh(_Symbol, PERIOD_M5, i);
         double l = iLow(_Symbol, PERIOD_M5, i);
         if(h > asianHigh) asianHigh = h;
         if(l < asianLow)  asianLow  = l;
      }
   }

   // London session (03:00-08:00 ET)
   londonHigh = -DBL_MAX;
   londonLow  = DBL_MAX;

   int londonStartBroker = (3 + InpBrokerGMTOffset + 5) % 24;
   int londonEndBroker   = (8 + InpBrokerGMTOffset + 5) % 24;

   for(int i = 1; i < 100; i++)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime bdt;
      TimeToStruct(barTime, bdt);
      datetime barDay = StringToTime(IntegerToString(bdt.year) + "." + 
                                      IntegerToString(bdt.mon) + "." + 
                                      IntegerToString(bdt.day));

      if(barDay != today) continue;

      int barHour = bdt.hour;
      if(barHour >= londonStartBroker && barHour < londonEndBroker)
      {
         double h = iHigh(_Symbol, PERIOD_M5, i);
         double l = iLow(_Symbol, PERIOD_M5, i);
         if(h > londonHigh) londonHigh = h;
         if(l < londonLow)  londonLow  = l;
      }
   }

   levelsCalculated = true;
   lastLevelCalcDay = today;
}

//+------------------------------------------------------------------+
//| Scan for Fair Value Gaps                                          |
//+------------------------------------------------------------------+
void ScanForFVGs()
{
   // Reset old FVGs
   int validCount = 0;
   for(int i = 0; i < fvgCount; i++)
   {
      if(!fvgZones[i].used && (Bars(_Symbol, PERIOD_M5) - fvgZones[i].barIndex) <= InpFVG_MaxAge)
      {
         if(validCount != i)
            fvgZones[validCount] = fvgZones[i];
         validCount++;
      }
   }
   fvgCount = validCount;
   ArrayResize(fvgZones, fvgCount + 20);

   // Scan last 3 bars for new FVGs (bar[2], bar[1], bar[0] pattern)
   for(int i = 2; i <= 5; i++)
   {
      double high_prev  = iHigh(_Symbol, PERIOD_M5, i);
      double low_prev   = iLow(_Symbol, PERIOD_M5, i);
      double high_curr  = iHigh(_Symbol, PERIOD_M5, i-1);
      double low_curr   = iLow(_Symbol, PERIOD_M5, i-1);
      double high_next  = iHigh(_Symbol, PERIOD_M5, i-2);
      double low_next   = iLow(_Symbol, PERIOD_M5, i-2);

      double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

      // Bullish FVG: high of bar[i] < low of bar[i-2]
      if(low_next > high_prev)
      {
         double gapSize = (low_next - high_prev) / point;
         if(gapSize >= InpFVG_MinSize)
         {
            // Check if this FVG already exists
            bool exists = false;
            for(int j = 0; j < fvgCount; j++)
            {
               if(MathAbs(fvgZones[j].top - low_next) < point && 
                  MathAbs(fvgZones[j].bottom - high_prev) < point)
               {
                  exists = true;
                  break;
               }
            }
            if(!exists)
            {
               ArrayResize(fvgZones, fvgCount + 1);
               fvgZones[fvgCount].top       = low_next;
               fvgZones[fvgCount].bottom    = high_prev;
               fvgZones[fvgCount].time      = iTime(_Symbol, PERIOD_M5, i-1);
               fvgZones[fvgCount].barIndex  = Bars(_Symbol, PERIOD_M5) - (i-1);
               fvgZones[fvgCount].isBullish = true;
               fvgZones[fvgCount].used      = false;
               fvgCount++;
            }
         }
      }

      // Bearish FVG: low of bar[i] > high of bar[i-2]
      if(high_next < low_prev)
      {
         double gapSize = (low_prev - high_next) / point;
         if(gapSize >= InpFVG_MinSize)
         {
            bool exists = false;
            for(int j = 0; j < fvgCount; j++)
            {
               if(MathAbs(fvgZones[j].top - low_prev) < point && 
                  MathAbs(fvgZones[j].bottom - high_next) < point)
               {
                  exists = true;
                  break;
               }
            }
            if(!exists)
            {
               ArrayResize(fvgZones, fvgCount + 1);
               fvgZones[fvgCount].top       = low_prev;
               fvgZones[fvgCount].bottom    = high_next;
               fvgZones[fvgCount].time      = iTime(_Symbol, PERIOD_M5, i-1);
               fvgZones[fvgCount].barIndex  = Bars(_Symbol, PERIOD_M5) - (i-1);
               fvgZones[fvgCount].isBullish = false;
               fvgZones[fvgCount].used      = false;
               fvgCount++;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check for liquidity sweep + FVG entry setup                       |
//+------------------------------------------------------------------+
void CheckForSweepEntry()
{
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double bid   = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask   = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

   // Get recent candle data
   double high1  = iHigh(_Symbol, PERIOD_M5, 1);
   double low1   = iLow(_Symbol, PERIOD_M5, 1);
   double open1  = iOpen(_Symbol, PERIOD_M5, 1);
   double close1 = iClose(_Symbol, PERIOD_M5, 1);

   double high2  = iHigh(_Symbol, PERIOD_M5, 2);
   double low2   = iLow(_Symbol, PERIOD_M5, 2);
   double open2  = iOpen(_Symbol, PERIOD_M5, 2);
   double close2 = iClose(_Symbol, PERIOD_M5, 2);

   // Check levels for sweep
   double sweepLevelsHigh[];
   double sweepLevelsLow[];
   string sweepLabelsHigh[];
   string sweepLabelsLow[];

   int hCount = 0, lCount = 0;

   // Add valid levels
   if(asianHigh > 0 && asianHigh != -DBL_MAX)
   { ArrayResize(sweepLevelsHigh, hCount+1); ArrayResize(sweepLabelsHigh, hCount+1);
     sweepLevelsHigh[hCount] = asianHigh; sweepLabelsHigh[hCount] = "Asian_High"; hCount++; }
   if(londonHigh > 0 && londonHigh != -DBL_MAX)
   { ArrayResize(sweepLevelsHigh, hCount+1); ArrayResize(sweepLabelsHigh, hCount+1);
     sweepLevelsHigh[hCount] = londonHigh; sweepLabelsHigh[hCount] = "London_High"; hCount++; }
   if(prevDayHigh > 0 && prevDayHigh != -DBL_MAX)
   { ArrayResize(sweepLevelsHigh, hCount+1); ArrayResize(sweepLabelsHigh, hCount+1);
     sweepLevelsHigh[hCount] = prevDayHigh; sweepLabelsHigh[hCount] = "PrevDay_High"; hCount++; }

   if(asianLow > 0 && asianLow != DBL_MAX)
   { ArrayResize(sweepLevelsLow, lCount+1); ArrayResize(sweepLabelsLow, lCount+1);
     sweepLevelsLow[lCount] = asianLow; sweepLabelsLow[lCount] = "Asian_Low"; lCount++; }
   if(londonLow > 0 && londonLow != DBL_MAX)
   { ArrayResize(sweepLevelsLow, lCount+1); ArrayResize(sweepLabelsLow, lCount+1);
     sweepLevelsLow[lCount] = londonLow; sweepLabelsLow[lCount] = "London_Low"; lCount++; }
   if(prevDayLow > 0 && prevDayLow != DBL_MAX)
   { ArrayResize(sweepLevelsLow, lCount+1); ArrayResize(sweepLabelsLow, lCount+1);
     sweepLevelsLow[lCount] = prevDayLow; sweepLabelsLow[lCount] = "PrevDay_Low"; lCount++; }

   // === BEARISH SETUP: Sweep of highs + bearish displacement + bearish FVG ===
   for(int h = 0; h < hCount; h++)
   {
      double level = sweepLevelsHigh[h];
      double sweepAmount = (high2 - level) / point;

      // Bar[2] swept above the level
      if(high2 > level && sweepAmount >= InpSweepMinPips && sweepAmount <= InpSweepMaxPips)
      {
         // Bar[2] closed back below (or bar[1] is bearish displacement)
         bool sweptBack = (close2 < level) || (close1 < level);

         if(sweptBack)
         {
            // Check displacement
            if(InpRequireDisplacement)
            {
               double dispBody = MathAbs(close1 - open1) / point;
               bool isBearishDisp = (close1 < open1) && (dispBody >= InpDisplacementMinPips);
               if(!isBearishDisp) continue;
            }

            // Find bearish FVG near current price
            for(int f = 0; f < fvgCount; f++)
            {
               if(fvgZones[f].used || fvgZones[f].isBullish) continue;

               double fvgMid = (fvgZones[f].top + fvgZones[f].bottom) / 2.0;

               // Price approaching FVG from below (retracing into bearish FVG)
               if(bid >= fvgZones[f].bottom && bid <= fvgZones[f].top)
               {
                  // SELL entry
                  double sl = high2 + InpSweepMinPips * point; // Above the sweep wick
                  double slDist = sl - bid;
                  double tp = bid - slDist * InpRR_Ratio;

                  double lots = CalculateLotSize(slDist);
                  if(lots <= 0) continue;

                  if(trade.Sell(lots, _Symbol, bid, sl, tp, InpTradeComment + "_" + sweepLabelsHigh[h]))
                  {
                     fvgZones[f].used = true;
                     dailyTrades++;
                     Print("SELL: Sweep of ", sweepLabelsHigh[h], " | FVG Entry | Lots: ", lots);
                     return;
                  }
               }
            }
         }
      }
   }

   // === BULLISH SETUP: Sweep of lows + bullish displacement + bullish FVG ===
   for(int l = 0; l < lCount; l++)
   {
      double level = sweepLevelsLow[l];
      double sweepAmount = (level - low2) / point;

      // Bar[2] swept below the level
      if(low2 < level && sweepAmount >= InpSweepMinPips && sweepAmount <= InpSweepMaxPips)
      {
         // Bar[2] or bar[1] closed back above
         bool sweptBack = (close2 > level) || (close1 > level);

         if(sweptBack)
         {
            // Check displacement
            if(InpRequireDisplacement)
            {
               double dispBody = MathAbs(close1 - open1) / point;
               bool isBullishDisp = (close1 > open1) && (dispBody >= InpDisplacementMinPips);
               if(!isBullishDisp) continue;
            }

            // Find bullish FVG near current price
            for(int f = 0; f < fvgCount; f++)
            {
               if(fvgZones[f].used || !fvgZones[f].isBullish) continue;

               // Price retracing down into bullish FVG
               if(ask <= fvgZones[f].top && ask >= fvgZones[f].bottom)
               {
                  // BUY entry
                  double sl = low2 - InpSweepMinPips * point; // Below the sweep wick
                  double slDist = ask - sl;
                  double tp = ask + slDist * InpRR_Ratio;

                  double lots = CalculateLotSize(slDist);
                  if(lots <= 0) continue;

                  if(trade.Buy(lots, _Symbol, ask, sl, tp, InpTradeComment + "_" + sweepLabelsLow[l]))
                  {
                     fvgZones[f].used = true;
                     dailyTrades++;
                     Print("BUY: Sweep of ", sweepLabelsLow[l], " | FVG Entry | Lots: ", lots);
                     return;
                  }
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check if current time is within trading session                   |
//+------------------------------------------------------------------+
bool IsInSession()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   // Convert broker time to ET
   int etHour = dt.hour - InpBrokerGMTOffset - 5;
   if(etHour < 0) etHour += 24;
   int etMin  = dt.min;

   int currentMinET = etHour * 60 + etMin;
   int sessionStart = InpSessionStartHour * 60 + InpSessionStartMin;
   int sessionEnd   = InpSessionEndHour * 60 + InpSessionEndMin;

   return (currentMinET >= sessionStart && currentMinET <= sessionEnd);
}

//+------------------------------------------------------------------+
//| Calculate lot size based on risk                                  |
//+------------------------------------------------------------------+
double CalculateLotSize(double slDistance)
{
   if(slDistance <= 0) return 0;

   double balance   = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskMoney = balance * InpRiskPercent / 100.0;

   double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize == 0 || tickValue == 0) return 0;

   double lots = riskMoney / (slDistance / tickSize * tickValue);

   double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lotMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   // Cap at 20 lots (Funding Pips limit)
   lotMax = MathMin(lotMax, 20.0);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, lotMin);
   lots = MathMin(lots, lotMax);

   return lots;
}

//+------------------------------------------------------------------+
//| Check risk limits                                                 |
//+------------------------------------------------------------------+
bool CheckRiskLimits()
{
   // Max trades per day
   if(dailyTrades >= InpMaxTradesPerDay) return false;

   // Consecutive losses circuit breaker
   if(consecLosses >= InpMaxConsecLosses) return false;

   // Daily loss limit
   double balance = AccountInfoDouble(ACCOUNT_BALANCE);
   if(dailyPnL <= -(balance * InpDailyLossLimit / 100.0)) return false;

   // Max drawdown
   double dd = (peakBalance - balance) / initialBalance * 100.0;
   if(dd >= InpMaxDrawdownPct) return false;

   return true;
}

//+------------------------------------------------------------------+
//| Update drawdown tracking                                          |
//+------------------------------------------------------------------+
void UpdateDrawdown()
{
   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   if(equity > peakBalance) peakBalance = equity;

   double dd = (peakBalance - equity) / initialBalance * 100.0;
   if(dd > maxDrawdown) maxDrawdown = dd;
}

//+------------------------------------------------------------------+
//| Manage existing positions                                         |
//+------------------------------------------------------------------+
void ManagePositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() != InpMagicNumber) continue;
      if(posInfo.Symbol() != _Symbol) continue;

      // Check min duration before allowing close
      int duration = (int)(TimeCurrent() - posInfo.Time());
      if(duration < InpMinTradeDuration) continue;

      // Position is managed by SL/TP - no additional logic needed here
      // Could add breakeven/trailing logic in future iterations
   }
}

//+------------------------------------------------------------------+
//| Check if we have an open position                                 |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() != InpMagicNumber && posInfo.Symbol() == _Symbol)
         continue;
      if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| OnTradeTransaction - Track trade results                          |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request,
                        const MqlTradeResult &result)
{
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD)
   {
      long dealEntry;
      if(HistoryDealSelect(trans.deal))
      {
         dealEntry = HistoryDealGetInteger(trans.deal, DEAL_ENTRY);
         long dealMagic = HistoryDealGetInteger(trans.deal, DEAL_MAGIC);

         if(dealMagic == InpMagicNumber && dealEntry == DEAL_ENTRY_OUT)
         {
            double profit = HistoryDealGetDouble(trans.deal, DEAL_PROFIT);
            double commission = HistoryDealGetDouble(trans.deal, DEAL_COMMISSION);
            double swap = HistoryDealGetDouble(trans.deal, DEAL_SWAP);
            double totalPnL = profit + commission + swap;

            dailyPnL += totalPnL;
            totalTrades++;

            if(totalPnL >= 0)
            {
               wins++;
               consecLosses = 0;
            }
            else
            {
               losses++;
               consecLosses++;
            }

            // Log trade
            int idx = ArraySize(tradeLog);
            ArrayResize(tradeLog, idx + 1);
            tradeLog[idx].ticket      = (int)trans.deal;
            tradeLog[idx].closeTime   = TimeCurrent();
            tradeLog[idx].pnl         = totalPnL;
            tradeLog[idx].lots        = HistoryDealGetDouble(trans.deal, DEAL_VOLUME);
            tradeLog[idx].exitPrice   = HistoryDealGetDouble(trans.deal, DEAL_PRICE);
            tradeLog[idx].direction   = (HistoryDealGetInteger(trans.deal, DEAL_TYPE) == DEAL_TYPE_BUY) ? "SELL_Close" : "BUY_Close";
            tradeLog[idx].balanceAfter = AccountInfoDouble(ACCOUNT_BALANCE);
            tradeLog[idx].sweepType   = HistoryDealGetString(trans.deal, DEAL_COMMENT);

            Print("Trade closed: PnL=", DoubleToString(totalPnL, 2), 
                  " | Daily PnL=", DoubleToString(dailyPnL, 2),
                  " | W/L: ", wins, "/", losses);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Generate CSV Report                                                |
//+------------------------------------------------------------------+
void GenerateCSVReport()
{
   int handle = FileOpen(InpCSVFilename, FILE_WRITE | FILE_CSV | FILE_COMMON, ",");
   if(handle == INVALID_HANDLE)
   {
      Print("Error opening CSV file: ", GetLastError());
      return;
   }

   // Header
   FileWrite(handle, "=== EA01: LIQUIDITY SWEEP + FVG ENTRY - BACKTEST REPORT ===");
   FileWrite(handle, "Symbol", _Symbol);
   FileWrite(handle, "Period", EnumToString(Period()));
   FileWrite(handle, "Date Generated", TimeToString(TimeCurrent()));
   FileWrite(handle, "Initial Balance", DoubleToString(initialBalance, 2));
   FileWrite(handle, "Final Balance", DoubleToString(AccountInfoDouble(ACCOUNT_BALANCE), 2));
   FileWrite(handle, "");

   // Summary Statistics
   FileWrite(handle, "=== SUMMARY STATISTICS ===");

   double finalBal = AccountInfoDouble(ACCOUNT_BALANCE);
   double netProfit = finalBal - initialBalance;
   double returnPct = (netProfit / initialBalance) * 100.0;
   double winRate = (totalTrades > 0) ? (double)wins / totalTrades * 100.0 : 0;

   // Calculate profit factor
   double grossProfit = 0, grossLoss = 0;
   double maxWin = 0, maxLoss = 0;
   double avgWin = 0, avgLoss = 0;
   int winCount = 0, lossCount = 0;
   double maxConsecWins = 0, maxConsecLosses_r = 0;
   int tempConsecW = 0, tempConsecL = 0;

   // Monthly breakdown arrays
   double monthlyPnL[];
   ArrayResize(monthlyPnL, 12);
   ArrayInitialize(monthlyPnL, 0);

   for(int i = 0; i < ArraySize(tradeLog); i++)
   {
      double pnl = tradeLog[i].pnl;
      if(pnl > 0)
      {
         grossProfit += pnl;
         winCount++;
         if(pnl > maxWin) maxWin = pnl;
         tempConsecW++;
         tempConsecL = 0;
         if(tempConsecW > maxConsecWins) maxConsecWins = tempConsecW;
      }
      else
      {
         grossLoss += MathAbs(pnl);
         lossCount++;
         if(MathAbs(pnl) > maxLoss) maxLoss = MathAbs(pnl);
         tempConsecL++;
         tempConsecW = 0;
         if(tempConsecL > maxConsecLosses_r) maxConsecLosses_r = tempConsecL;
      }

      MqlDateTime tdt;
      TimeToStruct(tradeLog[i].closeTime, tdt);
      if(tdt.mon >= 1 && tdt.mon <= 12)
         monthlyPnL[tdt.mon - 1] += pnl;
   }

   avgWin  = (winCount > 0) ? grossProfit / winCount : 0;
   avgLoss = (lossCount > 0) ? grossLoss / lossCount : 0;
   double profitFactor = (grossLoss > 0) ? grossProfit / grossLoss : 0;
   double expectancy = (totalTrades > 0) ? netProfit / totalTrades : 0;
   double avgRR = (avgLoss > 0) ? avgWin / avgLoss : 0;

   FileWrite(handle, "Total Trades", IntegerToString(totalTrades));
   FileWrite(handle, "Wins", IntegerToString(wins));
   FileWrite(handle, "Losses", IntegerToString(losses));
   FileWrite(handle, "Win Rate %", DoubleToString(winRate, 2));
   FileWrite(handle, "Net Profit", DoubleToString(netProfit, 2));
   FileWrite(handle, "Return %", DoubleToString(returnPct, 2));
   FileWrite(handle, "Profit Factor", DoubleToString(profitFactor, 2));
   FileWrite(handle, "Expectancy/Trade", DoubleToString(expectancy, 2));
   FileWrite(handle, "Avg Win", DoubleToString(avgWin, 2));
   FileWrite(handle, "Avg Loss", DoubleToString(avgLoss, 2));
   FileWrite(handle, "Avg RR Achieved", DoubleToString(avgRR, 2));
   FileWrite(handle, "Max Win", DoubleToString(maxWin, 2));
   FileWrite(handle, "Max Loss", DoubleToString(maxLoss, 2));
   FileWrite(handle, "Max Consecutive Wins", DoubleToString(maxConsecWins, 0));
   FileWrite(handle, "Max Consecutive Losses", DoubleToString(maxConsecLosses_r, 0));
   FileWrite(handle, "Gross Profit", DoubleToString(grossProfit, 2));
   FileWrite(handle, "Gross Loss", DoubleToString(grossLoss, 2));
   FileWrite(handle, "Max Drawdown %", DoubleToString(maxDrawdown, 2));
   FileWrite(handle, "");

   // Parameters used
   FileWrite(handle, "=== PARAMETERS USED ===");
   FileWrite(handle, "LookbackBars", IntegerToString(InpLookbackBars));
   FileWrite(handle, "SweepMinPips", IntegerToString(InpSweepMinPips));
   FileWrite(handle, "SweepMaxPips", IntegerToString(InpSweepMaxPips));
   FileWrite(handle, "FVG_MinSize", IntegerToString(InpFVG_MinSize));
   FileWrite(handle, "FVG_MaxAge", IntegerToString(InpFVG_MaxAge));
   FileWrite(handle, "RequireDisplacement", IntegerToString(InpRequireDisplacement));
   FileWrite(handle, "DisplacementMinPips", IntegerToString(InpDisplacementMinPips));
   FileWrite(handle, "RiskPercent", DoubleToString(InpRiskPercent, 2));
   FileWrite(handle, "RR_Ratio", DoubleToString(InpRR_Ratio, 2));
   FileWrite(handle, "MaxTradesPerDay", IntegerToString(InpMaxTradesPerDay));
   FileWrite(handle, "SessionStart", IntegerToString(InpSessionStartHour) + ":" + IntegerToString(InpSessionStartMin));
   FileWrite(handle, "SessionEnd", IntegerToString(InpSessionEndHour) + ":" + IntegerToString(InpSessionEndMin));
   FileWrite(handle, "");

   // Monthly breakdown
   FileWrite(handle, "=== MONTHLY P&L ===");
   string months[] = {"Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"};
   for(int i = 0; i < 12; i++)
   {
      if(monthlyPnL[i] != 0)
         FileWrite(handle, months[i], DoubleToString(monthlyPnL[i], 2));
   }
   FileWrite(handle, "");

   // Trade log
   FileWrite(handle, "=== TRADE LOG ===");
   FileWrite(handle, "Ticket", "CloseTime", "Direction", "ExitPrice", "Lots", "PnL", "Balance", "SweepType");

   for(int i = 0; i < ArraySize(tradeLog); i++)
   {
      FileWrite(handle,
         IntegerToString(tradeLog[i].ticket),
         TimeToString(tradeLog[i].closeTime),
         tradeLog[i].direction,
         DoubleToString(tradeLog[i].exitPrice, (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS)),
         DoubleToString(tradeLog[i].lots, 2),
         DoubleToString(tradeLog[i].pnl, 2),
         DoubleToString(tradeLog[i].balanceAfter, 2),
         tradeLog[i].sweepType
      );
   }

   // Prop Firm Compliance Check
   FileWrite(handle, "");
   FileWrite(handle, "=== PROP FIRM COMPLIANCE (Funding Pips 2-Step) ===");
   FileWrite(handle, "Phase 1 Target (8%)", DoubleToString(initialBalance * 0.08, 2), 
             (returnPct >= 8) ? "PASSED" : "NOT MET");
   FileWrite(handle, "Phase 2 Target (5%)", DoubleToString(initialBalance * 0.05, 2), 
             (returnPct >= 5) ? "PASSED" : "NOT MET");
   FileWrite(handle, "Daily DD Limit (5%)", DoubleToString(initialBalance * 0.05, 2), "CHECK_MANUALLY");
   FileWrite(handle, "Total DD Limit (10%)", DoubleToString(initialBalance * 0.10, 2), 
             (maxDrawdown < 10) ? "PASSED" : "VIOLATED");

   FileClose(handle);
   Print("CSV Report generated: ", InpCSVFilename);
}
