//+------------------------------------------------------------------+
//| EA_02_OrderBlock_FVG.mq5                                         |
//| Strategy: Order Block + FVG Confluence Entry                     |
//| Assets: EUR/USD, GBP/USD, XAUUSD - NY Session                   |
//| Author: Jose - Prop Firm Challenge EA Suite                       |
//+------------------------------------------------------------------+
#property copyright "Jose - Quant Trading"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Input Parameters: Strategy
input group "=== STRATEGY PARAMETERS ==="
input int      InpOB_Lookback       = 50;       // Bars to scan for Order Blocks
input int      InpOB_ConsolidationBars = 3;     // Min bars in OB consolidation
input int      InpOB_BreakoutMinPips = 20;      // Min breakout from OB (points)
input int      InpFVG_MinSize       = 5;        // Min FVG size (points)
input int      InpFVG_MaxAge        = 15;       // Max bars old for valid FVG
input int      InpBOS_SwingLength   = 10;       // Swing detection lookback
input bool     InpRequireBOS        = true;     // Require BOS before OB entry
input double   InpOB_EntryPct       = 50.0;     // Entry at % of OB body (50=midpoint)
input int      InpHTF_Period        = PERIOD_H1; // Higher TF for bias

//--- Input Parameters: Session Filter
input group "=== SESSION FILTER ==="
input int      InpSessionStartHour  = 8;
input int      InpSessionStartMin   = 0;
input int      InpSessionEndHour    = 12;
input int      InpSessionEndMin     = 0;
input int      InpBrokerGMTOffset   = 2;

//--- Input Parameters: Risk Management
input group "=== RISK MANAGEMENT ==="
input double   InpRiskPercent       = 0.5;
input double   InpRR_Ratio          = 2.5;
input int      InpMaxTradesPerDay   = 3;
input int      InpMaxConsecLosses   = 3;
input double   InpDailyLossLimit    = 4.0;
input double   InpMaxDrawdownPct    = 8.0;
input int      InpMinTradeDuration  = 90;

//--- Input Parameters: Execution
input group "=== EXECUTION ==="
input int      InpMaxSpread         = 35;
input int      InpSlippage          = 10;
input int      InpMagicNumber       = 100200;
input string   InpTradeComment      = "OB_FVG";

//--- Input Parameters: Report
input group "=== REPORT ==="
input bool     InpGenerateCSV       = true;
input string   InpCSVFilename       = "EA02_OrderBlock_FVG_Report.csv";

//--- Global Variables
CTrade         trade;
CPositionInfo  posInfo;

struct OrderBlock {
   double   top;
   double   bottom;
   datetime time;
   int      barIndex;
   bool     isBullish;
   bool     used;
   bool     mitigated;
};

struct FVGZone {
   double   top;
   double   bottom;
   datetime time;
   int      barIndex;
   bool     isBullish;
   bool     used;
};

struct TradeRecord {
   int      ticket;
   datetime closeTime;
   string   direction;
   double   exitPrice;
   double   lots;
   double   pnl;
   double   balanceAfter;
   string   comment;
};

OrderBlock     obZones[];
int            obCount;
FVGZone        fvgZones[];
int            fvgCount;
TradeRecord    tradeLog[];

int            totalTrades, wins, losses;
int            dailyTrades, consecLosses;
double         dailyPnL, initialBalance, peakBalance, maxDrawdown;
datetime       lastTradeDay;

// Swing tracking
double         swingHighs[];
double         swingLows[];
datetime       swingHighTimes[];
datetime       swingLowTimes[];
int            lastBOSDirection; // 1=bullish, -1=bearish, 0=none

//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   initialBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   peakBalance = initialBalance;
   maxDrawdown = 0;
   totalTrades = wins = losses = 0;
   dailyTrades = consecLosses = 0;
   dailyPnL = 0;
   lastTradeDay = 0;
   obCount = fvgCount = 0;
   lastBOSDirection = 0;

   ArrayResize(tradeLog, 0);
   ArrayResize(obZones, 0);
   ArrayResize(fvgZones, 0);
   ArrayResize(swingHighs, 0);
   ArrayResize(swingLows, 0);

   Print("EA02 OrderBlock+FVG initialized. Balance: ", initialBalance);
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(InpGenerateCSV && ArraySize(tradeLog) > 0)
      GenerateCSVReport();
}

//+------------------------------------------------------------------+
void OnTick()
{
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   ResetDailyCounters();
   UpdateDrawdown();
   if(!CheckRiskLimits()) return;
   ManagePositions();

   if(!IsInSession()) return;
   if(SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) > InpMaxSpread) return;
   if(HasOpenPosition()) return;

   // Detect market structure
   DetectSwings();
   DetectBOS();

   // Detect Order Blocks
   DetectOrderBlocks();

   // Detect FVGs
   DetectFVGs();

   // Look for confluence entries
   CheckConfluenceEntry();
}

//+------------------------------------------------------------------+
//| Detect Swing Highs and Lows                                       |
//+------------------------------------------------------------------+
void DetectSwings()
{
   int len = InpBOS_SwingLength;

   ArrayResize(swingHighs, 0);
   ArrayResize(swingLows, 0);
   ArrayResize(swingHighTimes, 0);
   ArrayResize(swingLowTimes, 0);

   for(int i = len; i < InpOB_Lookback; i++)
   {
      double high_i = iHigh(_Symbol, PERIOD_M5, i);
      double low_i  = iLow(_Symbol, PERIOD_M5, i);

      // Swing High: highest in lookback window on both sides
      bool isSwingHigh = true;
      for(int j = 1; j <= len; j++)
      {
         if(iHigh(_Symbol, PERIOD_M5, i-j) > high_i || 
            iHigh(_Symbol, PERIOD_M5, i+j) > high_i)
         {
            isSwingHigh = false;
            break;
         }
      }

      if(isSwingHigh)
      {
         int idx = ArraySize(swingHighs);
         ArrayResize(swingHighs, idx + 1);
         ArrayResize(swingHighTimes, idx + 1);
         swingHighs[idx] = high_i;
         swingHighTimes[idx] = iTime(_Symbol, PERIOD_M5, i);
      }

      // Swing Low
      bool isSwingLow = true;
      for(int j = 1; j <= len; j++)
      {
         if(iLow(_Symbol, PERIOD_M5, i-j) < low_i || 
            iLow(_Symbol, PERIOD_M5, i+j) < low_i)
         {
            isSwingLow = false;
            break;
         }
      }

      if(isSwingLow)
      {
         int idx = ArraySize(swingLows);
         ArrayResize(swingLows, idx + 1);
         ArrayResize(swingLowTimes, idx + 1);
         swingLows[idx] = low_i;
         swingLowTimes[idx] = iTime(_Symbol, PERIOD_M5, i);
      }
   }
}

//+------------------------------------------------------------------+
//| Detect Break of Structure                                         |
//+------------------------------------------------------------------+
void DetectBOS()
{
   lastBOSDirection = 0;

   double close1 = iClose(_Symbol, PERIOD_M5, 1);

   // Bullish BOS: price breaks above most recent swing high
   if(ArraySize(swingHighs) > 0 && close1 > swingHighs[0])
      lastBOSDirection = 1;

   // Bearish BOS: price breaks below most recent swing low
   if(ArraySize(swingLows) > 0 && close1 < swingLows[0])
      lastBOSDirection = -1;
}

//+------------------------------------------------------------------+
//| Detect Order Blocks                                               |
//+------------------------------------------------------------------+
void DetectOrderBlocks()
{
   // Clean old/mitigated OBs
   int valid = 0;
   for(int i = 0; i < obCount; i++)
   {
      if(!obZones[i].used && !obZones[i].mitigated)
      {
         // Check if OB is mitigated (price passed through it)
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         if(obZones[i].isBullish && bid < obZones[i].bottom)
            obZones[i].mitigated = true;
         else if(!obZones[i].isBullish && bid > obZones[i].top)
            obZones[i].mitigated = true;

         if(!obZones[i].mitigated)
         {
            if(valid != i) obZones[valid] = obZones[i];
            valid++;
         }
      }
   }
   obCount = valid;

   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   // Scan for new Order Blocks
   // OB = last opposite candle before impulsive move
   for(int i = 3; i < InpOB_Lookback - 1; i++)
   {
      double open_i  = iOpen(_Symbol, PERIOD_M5, i);
      double close_i = iClose(_Symbol, PERIOD_M5, i);
      double high_i  = iHigh(_Symbol, PERIOD_M5, i);
      double low_i   = iLow(_Symbol, PERIOD_M5, i);

      // Check if candle after this one is impulsive
      double open_next  = iOpen(_Symbol, PERIOD_M5, i-1);
      double close_next = iClose(_Symbol, PERIOD_M5, i-1);
      double bodyNext   = MathAbs(close_next - open_next) / point;

      if(bodyNext < InpOB_BreakoutMinPips) continue;

      // Bullish OB: bearish candle [i] followed by bullish impulse [i-1]
      if(close_i < open_i && close_next > open_next)
      {
         // Verify the impulse broke structure (went above swing high)
         bool brokeSH = false;
         for(int s = 0; s < ArraySize(swingHighs); s++)
         {
            if(close_next > swingHighs[s] && swingHighTimes[s] > iTime(_Symbol, PERIOD_M5, i))
            {
               brokeSH = true;
               break;
            }
         }

         if(brokeSH || !InpRequireBOS)
         {
            bool exists = false;
            for(int j = 0; j < obCount; j++)
            {
               if(MathAbs(obZones[j].bottom - low_i) < point * 5 &&
                  MathAbs(obZones[j].top - high_i) < point * 5)
               { exists = true; break; }
            }

            if(!exists)
            {
               ArrayResize(obZones, obCount + 1);
               obZones[obCount].top       = high_i;
               obZones[obCount].bottom    = low_i;
               obZones[obCount].time      = iTime(_Symbol, PERIOD_M5, i);
               obZones[obCount].barIndex  = i;
               obZones[obCount].isBullish = true;
               obZones[obCount].used      = false;
               obZones[obCount].mitigated = false;
               obCount++;
            }
         }
      }

      // Bearish OB: bullish candle [i] followed by bearish impulse [i-1]
      if(close_i > open_i && close_next < open_next)
      {
         bool brokeSL = false;
         for(int s = 0; s < ArraySize(swingLows); s++)
         {
            if(close_next < swingLows[s] && swingLowTimes[s] > iTime(_Symbol, PERIOD_M5, i))
            {
               brokeSL = true;
               break;
            }
         }

         if(brokeSL || !InpRequireBOS)
         {
            bool exists = false;
            for(int j = 0; j < obCount; j++)
            {
               if(MathAbs(obZones[j].bottom - low_i) < point * 5 &&
                  MathAbs(obZones[j].top - high_i) < point * 5)
               { exists = true; break; }
            }

            if(!exists)
            {
               ArrayResize(obZones, obCount + 1);
               obZones[obCount].top       = high_i;
               obZones[obCount].bottom    = low_i;
               obZones[obCount].time      = iTime(_Symbol, PERIOD_M5, i);
               obZones[obCount].barIndex  = i;
               obZones[obCount].isBullish = false;
               obZones[obCount].used      = false;
               obZones[obCount].mitigated = false;
               obCount++;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Detect Fair Value Gaps                                             |
//+------------------------------------------------------------------+
void DetectFVGs()
{
   int valid = 0;
   for(int i = 0; i < fvgCount; i++)
   {
      int age = (int)(Bars(_Symbol, PERIOD_M5) - fvgZones[i].barIndex);
      if(!fvgZones[i].used && age <= InpFVG_MaxAge)
      {
         if(valid != i) fvgZones[valid] = fvgZones[i];
         valid++;
      }
   }
   fvgCount = valid;

   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   for(int i = 2; i <= 6; i++)
   {
      double high_prev = iHigh(_Symbol, PERIOD_M5, i);
      double low_next  = iLow(_Symbol, PERIOD_M5, i-2);
      double high_next = iHigh(_Symbol, PERIOD_M5, i-2);
      double low_prev  = iLow(_Symbol, PERIOD_M5, i);

      // Bullish FVG
      if(low_next > high_prev)
      {
         double gap = (low_next - high_prev) / point;
         if(gap >= InpFVG_MinSize)
         {
            bool exists = false;
            for(int j = 0; j < fvgCount; j++)
               if(MathAbs(fvgZones[j].top - low_next) < point && 
                  MathAbs(fvgZones[j].bottom - high_prev) < point)
               { exists = true; break; }

            if(!exists)
            {
               ArrayResize(fvgZones, fvgCount + 1);
               fvgZones[fvgCount].top       = low_next;
               fvgZones[fvgCount].bottom    = high_prev;
               fvgZones[fvgCount].time      = iTime(_Symbol, PERIOD_M5, i-1);
               fvgZones[fvgCount].barIndex  = Bars(_Symbol, PERIOD_M5) - (i-1);
               fvgZones[fvgCount].isBullish = true;
               fvgZones[fvgCount].used      = false;
               fvgCount++;
            }
         }
      }

      // Bearish FVG
      if(high_next < low_prev)
      {
         double gap = (low_prev - high_next) / point;
         if(gap >= InpFVG_MinSize)
         {
            bool exists = false;
            for(int j = 0; j < fvgCount; j++)
               if(MathAbs(fvgZones[j].top - low_prev) < point && 
                  MathAbs(fvgZones[j].bottom - high_next) < point)
               { exists = true; break; }

            if(!exists)
            {
               ArrayResize(fvgZones, fvgCount + 1);
               fvgZones[fvgCount].top       = low_prev;
               fvgZones[fvgCount].bottom    = high_next;
               fvgZones[fvgCount].time      = iTime(_Symbol, PERIOD_M5, i-1);
               fvgZones[fvgCount].barIndex  = Bars(_Symbol, PERIOD_M5) - (i-1);
               fvgZones[fvgCount].isBullish = false;
               fvgZones[fvgCount].used      = false;
               fvgCount++;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check for OB + FVG confluence entry                               |
//+------------------------------------------------------------------+
void CheckConfluenceEntry()
{
   double bid   = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask   = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   // Get HTF bias
   int htfBias = GetHTFBias();

   for(int ob = 0; ob < obCount; ob++)
   {
      if(obZones[ob].used || obZones[ob].mitigated) continue;

      for(int fvg = 0; fvg < fvgCount; fvg++)
      {
         if(fvgZones[fvg].used) continue;
         if(fvgZones[fvg].isBullish != obZones[ob].isBullish) continue;

         // Check overlap between OB and FVG
         double overlapTop = MathMin(obZones[ob].top, fvgZones[fvg].top);
         double overlapBot = MathMax(obZones[ob].bottom, fvgZones[fvg].bottom);

         if(overlapTop <= overlapBot) continue; // No overlap

         double confluenceZoneMid = (overlapTop + overlapBot) / 2.0;

         // === BULLISH CONFLUENCE ===
         if(obZones[ob].isBullish && (htfBias >= 0 || !InpRequireBOS))
         {
            // Price retracing into confluence zone
            if(ask >= overlapBot && ask <= overlapTop)
            {
               double entryPrice = obZones[ob].bottom + 
                  (obZones[ob].top - obZones[ob].bottom) * (InpOB_EntryPct / 100.0);

               double sl = obZones[ob].bottom - 5 * point;
               double slDist = ask - sl;
               double tp = ask + slDist * InpRR_Ratio;

               double lots = CalculateLotSize(slDist);
               if(lots <= 0) continue;

               if(trade.Buy(lots, _Symbol, ask, sl, tp, InpTradeComment + "_Bull"))
               {
                  obZones[ob].used = true;
                  fvgZones[fvg].used = true;
                  dailyTrades++;
                  Print("BUY: OB+FVG Confluence | OB: ", obZones[ob].bottom, "-", obZones[ob].top);
                  return;
               }
            }
         }

         // === BEARISH CONFLUENCE ===
         if(!obZones[ob].isBullish && (htfBias <= 0 || !InpRequireBOS))
         {
            if(bid >= overlapBot && bid <= overlapTop)
            {
               double sl = obZones[ob].top + 5 * point;
               double slDist = sl - bid;
               double tp = bid - slDist * InpRR_Ratio;

               double lots = CalculateLotSize(slDist);
               if(lots <= 0) continue;

               if(trade.Sell(lots, _Symbol, bid, sl, tp, InpTradeComment + "_Bear"))
               {
                  obZones[ob].used = true;
                  fvgZones[fvg].used = true;
                  dailyTrades++;
                  Print("SELL: OB+FVG Confluence | OB: ", obZones[ob].bottom, "-", obZones[ob].top);
                  return;
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Get Higher Timeframe Bias                                         |
//+------------------------------------------------------------------+
int GetHTFBias()
{
   // Simple: compare close vs open of last 3 HTF candles
   double close0 = iClose(_Symbol, (ENUM_TIMEFRAMES)InpHTF_Period, 0);
   double open3  = iOpen(_Symbol, (ENUM_TIMEFRAMES)InpHTF_Period, 3);

   if(close0 > open3) return 1;   // Bullish
   if(close0 < open3) return -1;  // Bearish
   return 0;
}

//+------------------------------------------------------------------+
//| Session, Risk, Position management - shared logic                 |
//+------------------------------------------------------------------+
bool IsInSession()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int etHour = dt.hour - InpBrokerGMTOffset - 5;
   if(etHour < 0) etHour += 24;
   int currentMinET = etHour * 60 + dt.min;
   int sessionStart = InpSessionStartHour * 60 + InpSessionStartMin;
   int sessionEnd   = InpSessionEndHour * 60 + InpSessionEndMin;
   return (currentMinET >= sessionStart && currentMinET <= sessionEnd);
}

double CalculateLotSize(double slDistance)
{
   if(slDistance <= 0) return 0;
   double balance   = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskMoney = balance * InpRiskPercent / 100.0;
   double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(tickSize == 0 || tickValue == 0) return 0;
   double lots = riskMoney / (slDistance / tickSize * tickValue);
   double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lotMax  = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 20.0);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   lots = MathFloor(lots / lotStep) * lotStep;
   return MathMax(MathMin(lots, lotMax), lotMin);
}

bool CheckRiskLimits()
{
   if(dailyTrades >= InpMaxTradesPerDay) return false;
   if(consecLosses >= InpMaxConsecLosses) return false;
   double balance = AccountInfoDouble(ACCOUNT_BALANCE);
   if(dailyPnL <= -(balance * InpDailyLossLimit / 100.0)) return false;
   double dd = (peakBalance - balance) / initialBalance * 100.0;
   if(dd >= InpMaxDrawdownPct) return false;
   return true;
}

void UpdateDrawdown()
{
   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   if(equity > peakBalance) peakBalance = equity;
   double dd = (peakBalance - equity) / initialBalance * 100.0;
   if(dd > maxDrawdown) maxDrawdown = dd;
}

void ResetDailyCounters()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year) + "." + 
                                  IntegerToString(dt.mon) + "." + IntegerToString(dt.day));
   if(today != lastTradeDay) { dailyTrades = 0; dailyPnL = 0; consecLosses = 0; lastTradeDay = today; }
}

void ManagePositions()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() != InpMagicNumber || posInfo.Symbol() != _Symbol) continue;
   }
}

bool HasOpenPosition()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol) return true;
   }
   return false;
}

//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request,
                        const MqlTradeResult &result)
{
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD)
   {
      if(HistoryDealSelect(trans.deal))
      {
         long dealEntry = HistoryDealGetInteger(trans.deal, DEAL_ENTRY);
         long dealMagic = HistoryDealGetInteger(trans.deal, DEAL_MAGIC);

         if(dealMagic == InpMagicNumber && dealEntry == DEAL_ENTRY_OUT)
         {
            double profit = HistoryDealGetDouble(trans.deal, DEAL_PROFIT) +
                           HistoryDealGetDouble(trans.deal, DEAL_COMMISSION) +
                           HistoryDealGetDouble(trans.deal, DEAL_SWAP);
            dailyPnL += profit;
            totalTrades++;
            if(profit >= 0) { wins++; consecLosses = 0; }
            else { losses++; consecLosses++; }

            int idx = ArraySize(tradeLog);
            ArrayResize(tradeLog, idx + 1);
            tradeLog[idx].ticket = (int)trans.deal;
            tradeLog[idx].closeTime = TimeCurrent();
            tradeLog[idx].pnl = profit;
            tradeLog[idx].lots = HistoryDealGetDouble(trans.deal, DEAL_VOLUME);
            tradeLog[idx].exitPrice = HistoryDealGetDouble(trans.deal, DEAL_PRICE);
            tradeLog[idx].balanceAfter = AccountInfoDouble(ACCOUNT_BALANCE);
            tradeLog[idx].comment = HistoryDealGetString(trans.deal, DEAL_COMMENT);
         }
      }
   }
}

//+------------------------------------------------------------------+
void GenerateCSVReport()
{
   int handle = FileOpen(InpCSVFilename, FILE_WRITE | FILE_CSV | FILE_COMMON, ",");
   if(handle == INVALID_HANDLE) return;

   FileWrite(handle, "=== EA02: ORDER BLOCK + FVG CONFLUENCE - BACKTEST REPORT ===");
   FileWrite(handle, "Symbol", _Symbol);
   FileWrite(handle, "Period", EnumToString(Period()));
   FileWrite(handle, "Date", TimeToString(TimeCurrent()));
   FileWrite(handle, "Initial Balance", DoubleToString(initialBalance, 2));
   FileWrite(handle, "Final Balance", DoubleToString(AccountInfoDouble(ACCOUNT_BALANCE), 2));
   FileWrite(handle, "");

   double finalBal = AccountInfoDouble(ACCOUNT_BALANCE);
   double netProfit = finalBal - initialBalance;
   double winRate = (totalTrades > 0) ? (double)wins / totalTrades * 100.0 : 0;
   double grossProfit = 0, grossLoss = 0;

   for(int i = 0; i < ArraySize(tradeLog); i++)
   {
      if(tradeLog[i].pnl > 0) grossProfit += tradeLog[i].pnl;
      else grossLoss += MathAbs(tradeLog[i].pnl);
   }

   double pf = (grossLoss > 0) ? grossProfit / grossLoss : 0;

   FileWrite(handle, "=== SUMMARY ===");
   FileWrite(handle, "Total Trades", IntegerToString(totalTrades));
   FileWrite(handle, "Wins", IntegerToString(wins));
   FileWrite(handle, "Losses", IntegerToString(losses));
   FileWrite(handle, "Win Rate %", DoubleToString(winRate, 2));
   FileWrite(handle, "Net Profit", DoubleToString(netProfit, 2));
   FileWrite(handle, "Return %", DoubleToString(netProfit / initialBalance * 100, 2));
   FileWrite(handle, "Profit Factor", DoubleToString(pf, 2));
   FileWrite(handle, "Expectancy", DoubleToString(totalTrades > 0 ? netProfit/totalTrades : 0, 2));
   FileWrite(handle, "Max Drawdown %", DoubleToString(maxDrawdown, 2));
   FileWrite(handle, "");

   FileWrite(handle, "=== PARAMETERS ===");
   FileWrite(handle, "OB_Lookback", IntegerToString(InpOB_Lookback));
   FileWrite(handle, "OB_BreakoutMinPips", IntegerToString(InpOB_BreakoutMinPips));
   FileWrite(handle, "FVG_MinSize", IntegerToString(InpFVG_MinSize));
   FileWrite(handle, "BOS_SwingLength", IntegerToString(InpBOS_SwingLength));
   FileWrite(handle, "RequireBOS", IntegerToString(InpRequireBOS));
   FileWrite(handle, "OB_EntryPct", DoubleToString(InpOB_EntryPct, 0));
   FileWrite(handle, "HTF_Period", EnumToString((ENUM_TIMEFRAMES)InpHTF_Period));
   FileWrite(handle, "RiskPercent", DoubleToString(InpRiskPercent, 2));
   FileWrite(handle, "RR_Ratio", DoubleToString(InpRR_Ratio, 2));
   FileWrite(handle, "");

   FileWrite(handle, "=== TRADE LOG ===");
   FileWrite(handle, "Ticket", "CloseTime", "PnL", "Lots", "Balance", "Comment");
   for(int i = 0; i < ArraySize(tradeLog); i++)
      FileWrite(handle, IntegerToString(tradeLog[i].ticket), TimeToString(tradeLog[i].closeTime),
                DoubleToString(tradeLog[i].pnl, 2), DoubleToString(tradeLog[i].lots, 2),
                DoubleToString(tradeLog[i].balanceAfter, 2), tradeLog[i].comment);

   FileWrite(handle, "");
   FileWrite(handle, "=== PROP FIRM CHECK ===");
   FileWrite(handle, "Max DD < 10%", (maxDrawdown < 10) ? "PASS" : "FAIL");
   FileWrite(handle, "Phase1 8% Target", (netProfit/initialBalance*100 >= 8) ? "PASS" : "NOT_MET");

   FileClose(handle);
   Print("EA02 CSV Report: ", InpCSVFilename);
}
