//+------------------------------------------------------------------+
//| EA_03_BOS_OB_Retrace.mq5                                        |
//| Strategy: Break of Structure + Retrace to Order Block            |
//| Assets: All - NY Session M5/M15 Scalping                        |
//| Author: Jose - Prop Firm Challenge EA Suite                       |
//+------------------------------------------------------------------+
#property copyright "Jose - Quant Trading"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Strategy
input group "=== STRATEGY ==="
input int      InpSwingLen          = 8;        // Swing detection length (bars each side)
input int      InpLookback          = 80;       // Max lookback for structure
input int      InpBOS_MinPips       = 10;       // Minimum BOS candle body (points)
input int      InpOB_MaxAge         = 20;       // Max bars old for valid OB
input double   InpOB_EntryPct       = 50.0;     // Entry at OB % (50=midpoint)
input bool     InpUseCHoCH          = true;     // Also trade CHoCH (counter-trend)
input int      InpMinImpulseCandles = 2;        // Min candles in impulse leg

//--- Session
input group "=== SESSION ==="
input int      InpStartHour         = 8;
input int      InpStartMin          = 0;
input int      InpEndHour           = 14;
input int      InpEndMin            = 0;
input int      InpGMTOffset         = 2;

//--- Risk
input group "=== RISK ==="
input double   InpRiskPct           = 0.5;
input double   InpRR                = 2.0;
input int      InpMaxDailyTrades    = 3;
input int      InpMaxConsecLoss     = 3;
input double   InpDailyLossLim      = 4.0;
input double   InpMaxDDPct          = 8.0;
input int      InpMinDuration       = 90;

//--- Execution
input group "=== EXECUTION ==="
input int      InpMaxSpread         = 40;
input int      InpSlippage          = 10;
input int      InpMagic             = 100300;
input string   InpComment           = "BOS_OB";

//--- Report
input group "=== REPORT ==="
input bool     InpCSV               = true;
input string   InpCSVFile           = "EA03_BOS_OB_Retrace_Report.csv";

CTrade trade;
CPositionInfo posInfo;

struct SwingPoint {
   double   price;
   datetime time;
   int      barIdx;
   bool     isHigh;
};

struct OBZone {
   double   top;
   double   bottom;
   datetime time;
   bool     isBullish;
   bool     used;
};

struct TradeRec {
   int ticket; datetime closeTime; double pnl; double lots;
   double balAfter; string comment; string bosType;
};

SwingPoint swings[];
OBZone     orderBlocks[];
int        obCount;
TradeRec   tradeLog[];

int totalTrades, wins, losses, dailyTrades, consecLosses;
double dailyPnL, initBal, peakBal, maxDD;
datetime lastDay;

// BOS state
int    lastBOSDir;     // 1=bullish BOS, -1=bearish BOS
double lastBOSPrice;
datetime lastBOSTime;

//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagic);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   initBal = AccountInfoDouble(ACCOUNT_BALANCE);
   peakBal = initBal;
   maxDD = 0; totalTrades = wins = losses = 0;
   dailyTrades = consecLosses = 0; dailyPnL = 0; lastDay = 0;
   obCount = 0; lastBOSDir = 0;
   ArrayResize(tradeLog, 0); ArrayResize(orderBlocks, 0); ArrayResize(swings, 0);
   Print("EA03 BOS+OB Retrace init. Bal: ", initBal);
   return INIT_SUCCEEDED;
}

void OnDeinit(const int reason)
{
   if(InpCSV && ArraySize(tradeLog) > 0) WriteReport();
}

//+------------------------------------------------------------------+
void OnTick()
{
   static datetime lastBar = 0;
   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   if(curBar == lastBar) return;
   lastBar = curBar;

   // Daily reset
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year)+"."+IntegerToString(dt.mon)+"."+IntegerToString(dt.day));
   if(today != lastDay) { dailyTrades=0; dailyPnL=0; consecLosses=0; lastDay=today; }

   // Drawdown
   double eq = AccountInfoDouble(ACCOUNT_EQUITY);
   if(eq > peakBal) peakBal = eq;
   double dd = (peakBal - eq) / initBal * 100.0;
   if(dd > maxDD) maxDD = dd;

   // Risk checks
   if(dailyTrades >= InpMaxDailyTrades) return;
   if(consecLosses >= InpMaxConsecLoss) return;
   double bal = AccountInfoDouble(ACCOUNT_BALANCE);
   if(dailyPnL <= -(bal * InpDailyLossLim / 100.0)) return;
   if(dd >= InpMaxDDPct) return;

   if(!InSession()) return;
   if(SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) > InpMaxSpread) return;
   if(HasPos()) return;

   // Detect structure
   FindSwings();
   DetectBOS();
   FindOBFromBOS();
   CheckOBEntry();
}

//+------------------------------------------------------------------+
void FindSwings()
{
   ArrayResize(swings, 0);
   int len = InpSwingLen;

   for(int i = len; i < InpLookback; i++)
   {
      double hi = iHigh(_Symbol, PERIOD_M5, i);
      double lo = iLow(_Symbol, PERIOD_M5, i);

      bool isSH = true, isSL = true;
      for(int j = 1; j <= len; j++)
      {
         if(iHigh(_Symbol, PERIOD_M5, i-j) > hi || iHigh(_Symbol, PERIOD_M5, i+j) > hi) isSH = false;
         if(iLow(_Symbol, PERIOD_M5, i-j) < lo || iLow(_Symbol, PERIOD_M5, i+j) < lo) isSL = false;
      }

      if(isSH)
      {
         int idx = ArraySize(swings);
         ArrayResize(swings, idx+1);
         swings[idx].price = hi;
         swings[idx].time = iTime(_Symbol, PERIOD_M5, i);
         swings[idx].barIdx = i;
         swings[idx].isHigh = true;
      }
      if(isSL)
      {
         int idx = ArraySize(swings);
         ArrayResize(swings, idx+1);
         swings[idx].price = lo;
         swings[idx].time = iTime(_Symbol, PERIOD_M5, i);
         swings[idx].barIdx = i;
         swings[idx].isHigh = false;
      }
   }
}

//+------------------------------------------------------------------+
void DetectBOS()
{
   if(ArraySize(swings) < 2) return;

   double close1 = iClose(_Symbol, PERIOD_M5, 1);
   double close2 = iClose(_Symbol, PERIOD_M5, 2);
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   // Find most recent swing high and low
   double recentSH = 0, recentSL = DBL_MAX;

   for(int i = 0; i < ArraySize(swings); i++)
   {
      if(swings[i].isHigh && swings[i].price > recentSH) recentSH = swings[i].price;
      if(!swings[i].isHigh && swings[i].price < recentSL) recentSL = swings[i].price;
      if(i >= 3) break; // Only check recent swings
   }

   int prevDir = lastBOSDir;

   // Bullish BOS: close above recent swing high
   if(recentSH > 0 && close1 > recentSH && (close1 - recentSH)/point >= InpBOS_MinPips)
   {
      lastBOSDir = 1;
      lastBOSPrice = recentSH;
      lastBOSTime = TimeCurrent();
   }

   // Bearish BOS: close below recent swing low
   if(recentSL < DBL_MAX && close1 < recentSL && (recentSL - close1)/point >= InpBOS_MinPips)
   {
      lastBOSDir = -1;
      lastBOSPrice = recentSL;
      lastBOSTime = TimeCurrent();
   }

   // CHoCH: direction change
   if(InpUseCHoCH && prevDir != 0 && lastBOSDir != 0 && prevDir != lastBOSDir)
   {
      // CHoCH detected - higher priority signal
      Print("CHoCH detected: ", prevDir > 0 ? "Bull->Bear" : "Bear->Bull");
   }
}

//+------------------------------------------------------------------+
void FindOBFromBOS()
{
   if(lastBOSDir == 0) return;

   // Clean old OBs
   int valid = 0;
   for(int i = 0; i < obCount; i++)
   {
      if(!orderBlocks[i].used)
      {
         if(valid != i) orderBlocks[valid] = orderBlocks[i];
         valid++;
      }
   }
   obCount = valid;

   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   // Find OB: last opposite candle before the impulse that caused BOS
   // Scan backwards from bar 1
   for(int i = 2; i < 20; i++)
   {
      double o = iOpen(_Symbol, PERIOD_M5, i);
      double c = iClose(_Symbol, PERIOD_M5, i);
      double h = iHigh(_Symbol, PERIOD_M5, i);
      double l = iLow(_Symbol, PERIOD_M5, i);

      // For bullish BOS: find the last bearish candle (OB = demand zone)
      if(lastBOSDir == 1 && c < o)
      {
         // Verify impulse after this candle
         bool hasImpulse = false;
         int impulseCount = 0;
         for(int j = i-1; j >= 1; j--)
         {
            if(iClose(_Symbol, PERIOD_M5, j) > iOpen(_Symbol, PERIOD_M5, j))
               impulseCount++;
            if(impulseCount >= InpMinImpulseCandles) { hasImpulse = true; break; }
         }

         if(hasImpulse)
         {
            bool exists = false;
            for(int j = 0; j < obCount; j++)
               if(MathAbs(orderBlocks[j].bottom - l) < point*5 && orderBlocks[j].isBullish)
               { exists = true; break; }

            if(!exists)
            {
               ArrayResize(orderBlocks, obCount+1);
               orderBlocks[obCount].top = h;
               orderBlocks[obCount].bottom = l;
               orderBlocks[obCount].time = iTime(_Symbol, PERIOD_M5, i);
               orderBlocks[obCount].isBullish = true;
               orderBlocks[obCount].used = false;
               obCount++;
            }
            break;
         }
      }

      // For bearish BOS: find the last bullish candle (OB = supply zone)
      if(lastBOSDir == -1 && c > o)
      {
         bool hasImpulse = false;
         int impulseCount = 0;
         for(int j = i-1; j >= 1; j--)
         {
            if(iClose(_Symbol, PERIOD_M5, j) < iOpen(_Symbol, PERIOD_M5, j))
               impulseCount++;
            if(impulseCount >= InpMinImpulseCandles) { hasImpulse = true; break; }
         }

         if(hasImpulse)
         {
            bool exists = false;
            for(int j = 0; j < obCount; j++)
               if(MathAbs(orderBlocks[j].top - h) < point*5 && !orderBlocks[j].isBullish)
               { exists = true; break; }

            if(!exists)
            {
               ArrayResize(orderBlocks, obCount+1);
               orderBlocks[obCount].top = h;
               orderBlocks[obCount].bottom = l;
               orderBlocks[obCount].time = iTime(_Symbol, PERIOD_M5, i);
               orderBlocks[obCount].isBullish = false;
               orderBlocks[obCount].used = false;
               obCount++;
            }
            break;
         }
      }
   }
}

//+------------------------------------------------------------------+
void CheckOBEntry()
{
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   for(int i = 0; i < obCount; i++)
   {
      if(orderBlocks[i].used) continue;

      // Check age
      int barsAgo = iBarShift(_Symbol, PERIOD_M5, orderBlocks[i].time);
      if(barsAgo > InpOB_MaxAge) { orderBlocks[i].used = true; continue; }

      double obMid = orderBlocks[i].bottom + 
         (orderBlocks[i].top - orderBlocks[i].bottom) * (InpOB_EntryPct / 100.0);

      // Bullish OB - BUY when price retraces into OB
      if(orderBlocks[i].isBullish && lastBOSDir == 1)
      {
         if(ask >= orderBlocks[i].bottom && ask <= orderBlocks[i].top)
         {
            double sl = orderBlocks[i].bottom - 5 * point;
            double slDist = ask - sl;
            double tp = ask + slDist * InpRR;
            double lots = CalcLots(slDist);
            if(lots <= 0) continue;

            if(trade.Buy(lots, _Symbol, ask, sl, tp, InpComment+"_BullBOS"))
            {
               orderBlocks[i].used = true;
               dailyTrades++;
               return;
            }
         }
      }

      // Bearish OB - SELL
      if(!orderBlocks[i].isBullish && lastBOSDir == -1)
      {
         if(bid >= orderBlocks[i].bottom && bid <= orderBlocks[i].top)
         {
            double sl = orderBlocks[i].top + 5 * point;
            double slDist = sl - bid;
            double tp = bid - slDist * InpRR;
            double lots = CalcLots(slDist);
            if(lots <= 0) continue;

            if(trade.Sell(lots, _Symbol, bid, sl, tp, InpComment+"_BearBOS"))
            {
               orderBlocks[i].used = true;
               dailyTrades++;
               return;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
// Utility functions
bool InSession()
{
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   int etH = dt.hour - InpGMTOffset - 5;
   if(etH < 0) etH += 24;
   int cur = etH*60+dt.min;
   return (cur >= InpStartHour*60+InpStartMin && cur <= InpEndHour*60+InpEndMin);
}

double CalcLots(double slDist)
{
   if(slDist <= 0) return 0;
   double bal = AccountInfoDouble(ACCOUNT_BALANCE);
   double risk = bal * InpRiskPct / 100.0;
   double tv = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double ts = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(ts == 0 || tv == 0) return 0;
   double lots = risk / (slDist / ts * tv);
   double lMin = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lMax = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 20.0);
   double lStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   lots = MathFloor(lots / lStep) * lStep;
   return MathMax(MathMin(lots, lMax), lMin);
}

bool HasPos()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   { if(!posInfo.SelectByIndex(i)) continue;
     if(posInfo.Magic() == InpMagic && posInfo.Symbol() == _Symbol) return true; }
   return false;
}

//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request,
                        const MqlTradeResult &result)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
   if(!HistoryDealSelect(trans.deal)) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_MAGIC) != InpMagic) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;

   double profit = HistoryDealGetDouble(trans.deal, DEAL_PROFIT) +
                   HistoryDealGetDouble(trans.deal, DEAL_COMMISSION) +
                   HistoryDealGetDouble(trans.deal, DEAL_SWAP);
   dailyPnL += profit;
   totalTrades++;
   if(profit >= 0) { wins++; consecLosses=0; } else { losses++; consecLosses++; }

   int idx = ArraySize(tradeLog);
   ArrayResize(tradeLog, idx+1);
   tradeLog[idx].ticket = (int)trans.deal;
   tradeLog[idx].closeTime = TimeCurrent();
   tradeLog[idx].pnl = profit;
   tradeLog[idx].lots = HistoryDealGetDouble(trans.deal, DEAL_VOLUME);
   tradeLog[idx].balAfter = AccountInfoDouble(ACCOUNT_BALANCE);
   tradeLog[idx].comment = HistoryDealGetString(trans.deal, DEAL_COMMENT);
   tradeLog[idx].bosType = (lastBOSDir == 1) ? "BullBOS" : (lastBOSDir == -1) ? "BearBOS" : "None";
}

//+------------------------------------------------------------------+
void WriteReport()
{
   int h = FileOpen(InpCSVFile, FILE_WRITE|FILE_CSV|FILE_COMMON, ",");
   if(h == INVALID_HANDLE) return;

   double finalBal = AccountInfoDouble(ACCOUNT_BALANCE);
   double net = finalBal - initBal;
   double wr = totalTrades > 0 ? (double)wins/totalTrades*100 : 0;
   double gp = 0, gl = 0;
   for(int i = 0; i < ArraySize(tradeLog); i++)
   { if(tradeLog[i].pnl > 0) gp += tradeLog[i].pnl; else gl += MathAbs(tradeLog[i].pnl); }
   double pf = gl > 0 ? gp/gl : 0;

   FileWrite(h, "=== EA03: BOS + OB RETRACE - BACKTEST REPORT ===");
   FileWrite(h, "Symbol", _Symbol); FileWrite(h, "Period", EnumToString(Period()));
   FileWrite(h, "Initial Balance", DoubleToString(initBal,2));
   FileWrite(h, "Final Balance", DoubleToString(finalBal,2));
   FileWrite(h, "");
   FileWrite(h, "=== SUMMARY ===");
   FileWrite(h, "Total Trades", IntegerToString(totalTrades));
   FileWrite(h, "Win Rate %", DoubleToString(wr,2));
   FileWrite(h, "Profit Factor", DoubleToString(pf,2));
   FileWrite(h, "Net Profit", DoubleToString(net,2));
   FileWrite(h, "Return %", DoubleToString(net/initBal*100,2));
   FileWrite(h, "Max DD %", DoubleToString(maxDD,2));
   FileWrite(h, "Expectancy", DoubleToString(totalTrades>0?net/totalTrades:0,2));
   FileWrite(h, "");
   FileWrite(h, "=== PARAMETERS ===");
   FileWrite(h, "SwingLen", IntegerToString(InpSwingLen));
   FileWrite(h, "BOS_MinPips", IntegerToString(InpBOS_MinPips));
   FileWrite(h, "OB_MaxAge", IntegerToString(InpOB_MaxAge));
   FileWrite(h, "OB_EntryPct", DoubleToString(InpOB_EntryPct,0));
   FileWrite(h, "UseCHoCH", IntegerToString(InpUseCHoCH));
   FileWrite(h, "RR", DoubleToString(InpRR,1));
   FileWrite(h, "");
   FileWrite(h, "=== TRADES ===");
   FileWrite(h, "Ticket","Time","PnL","Lots","Balance","BOSType","Comment");
   for(int i = 0; i < ArraySize(tradeLog); i++)
      FileWrite(h, IntegerToString(tradeLog[i].ticket), TimeToString(tradeLog[i].closeTime),
                DoubleToString(tradeLog[i].pnl,2), DoubleToString(tradeLog[i].lots,2),
                DoubleToString(tradeLog[i].balAfter,2), tradeLog[i].bosType, tradeLog[i].comment);

   FileWrite(h, ""); FileWrite(h, "=== PROP CHECK ===");
   FileWrite(h, "Max DD < 10%", maxDD < 10 ? "PASS" : "FAIL");
   FileClose(h);
   Print("EA03 Report: ", InpCSVFile);
}
