// VWAP calculation
double vwap_value;
double vwap_upper1, vwap_lower1;
double vwap_upper2, vwap_lower2;
double cumVolPrice, cumVol, cumVolPriceSq;
int    vwapBarCount;
datetime vwapSessionStart;

// OB/FVG from previous EAs - simplified
struct Zone { double top; double bottom; bool isBullish; bool used; datetime time; };
Zone obZones[]; int obCnt;
Zone fvgZones[]; int fvgCnt;

