//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagic);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   initBal = AccountInfoDouble(ACCOUNT_BALANCE);
   peakBal = initBal; maxDD = 0;
   totalTrades = wins = losses = dailyTrades = consecLosses = 0;
   dailyPnL = 0; lastDay = 0;
   obCnt = fvgCnt = 0;
   vwap_value = 0; cumVolPrice = 0; cumVol = 0; cumVolPriceSq = 0; vwapBarCount = 0;
   vwapSessionStart = 0;
   ArrayResize(tradeLog, 0); ArrayResize(obZones, 0); ArrayResize(fvgZones, 0);
   Print("EA04 VWAP+SMC init. Bal: ", initBal);
   return INIT_SUCCEEDED;
}

void OnDeinit(const int reason)
{
   if(InpCSV && ArraySize(tradeLog) > 0) WriteReport();
}

//+------------------------------------------------------------------+
void OnTick()
{
   static datetime lastBar = 0;
   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   if(curBar == lastBar) return;
   lastBar = curBar;

   // Daily reset
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year)+"."+IntegerToString(dt.mon)+"."+IntegerToString(dt.day));
   if(today != lastDay)
   {
      dailyTrades = 0; dailyPnL = 0; consecLosses = 0; lastDay = today;
      // Reset VWAP for new session
      cumVolPrice = 0; cumVol = 0; cumVolPriceSq = 0; vwapBarCount = 0;
      vwapSessionStart = TimeCurrent();
   }

   // Drawdown
   double eq = AccountInfoDouble(ACCOUNT_EQUITY);
   if(eq > peakBal) peakBal = eq;
   double dd = (peakBal - eq) / initBal * 100.0;
   if(dd > maxDD) maxDD = dd;

   // Risk
   if(dailyTrades >= InpMaxDailyTrades) return;
   double bal = AccountInfoDouble(ACCOUNT_BALANCE);
   if(dailyPnL <= -(bal * InpDailyLossLim / 100.0)) return;
   if(dd >= InpMaxDDPct) return;

   // Calculate VWAP
   CalculateVWAP();

   if(!InSession()) return;
   if(SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) > InpMaxSpread) return;
   if(HasPos()) return;

   // Detect zones
   DetectOBs();
   DetectFVGs();

   // Entry logic
   CheckVWAPEntry();
}

//+------------------------------------------------------------------+
//| Calculate Session VWAP with Standard Deviation Bands              |
//+------------------------------------------------------------------+
void CalculateVWAP()
{
   // Use tick volume as proxy (standard for CFDs)
   double close1 = iClose(_Symbol, PERIOD_M5, 1);
   double high1  = iHigh(_Symbol, PERIOD_M5, 1);
   double low1   = iLow(_Symbol, PERIOD_M5, 1);
   long   vol1   = iVolume(_Symbol, PERIOD_M5, 1);

   if(vol1 <= 0) vol1 = 1;

   double typicalPrice = (high1 + low1 + close1) / 3.0;

   cumVolPrice    += typicalPrice * (double)vol1;
   cumVol         += (double)vol1;
   cumVolPriceSq  += typicalPrice * typicalPrice * (double)vol1;
   vwapBarCount++;

   if(cumVol > 0)
   {
      vwap_value = cumVolPrice / cumVol;

      // Standard deviation
      double variance = (cumVolPriceSq / cumVol) - (vwap_value * vwap_value);
      double stdDev = (variance > 0) ? MathSqrt(variance) : 0;

      vwap_upper1 = vwap_value + stdDev * InpVWAP_StdDev1;
      vwap_lower1 = vwap_value - stdDev * InpVWAP_StdDev1;
      vwap_upper2 = vwap_value + stdDev * InpVWAP_StdDev2;
      vwap_lower2 = vwap_value - stdDev * InpVWAP_StdDev2;
   }
}

//+------------------------------------------------------------------+
void DetectOBs()
{
   // Clean
   int valid = 0;
   for(int i = 0; i < obCnt; i++)
      if(!obZones[i].used) { if(valid != i) obZones[valid] = obZones[i]; valid++; }
   obCnt = valid;

   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   for(int i = 3; i < InpOB_Lookback; i++)
   {
      double o = iOpen(_Symbol, PERIOD_M5, i);
      double c = iClose(_Symbol, PERIOD_M5, i);
      double h = iHigh(_Symbol, PERIOD_M5, i);
      double l = iLow(_Symbol, PERIOD_M5, i);
      double o_next = iOpen(_Symbol, PERIOD_M5, i-1);
      double c_next = iClose(_Symbol, PERIOD_M5, i-1);
      double body = MathAbs(c_next - o_next) / point;

      if(body < InpOB_MinBreakout) continue;

      // Bullish OB
      if(c < o && c_next > o_next)
      {
         bool exists = false;
         for(int j = 0; j < obCnt; j++)
            if(MathAbs(obZones[j].bottom - l) < point*5 && obZones[j].isBullish)
            { exists = true; break; }
         if(!exists && obCnt < 50)
         {
            ArrayResize(obZones, obCnt+1);
            obZones[obCnt].top = h; obZones[obCnt].bottom = l;
            obZones[obCnt].isBullish = true; obZones[obCnt].used = false;
            obZones[obCnt].time = iTime(_Symbol, PERIOD_M5, i);
            obCnt++;
         }
      }
      // Bearish OB
      if(c > o && c_next < o_next)
      {
         bool exists = false;
         for(int j = 0; j < obCnt; j++)
            if(MathAbs(obZones[j].top - h) < point*5 && !obZones[j].isBullish)
            { exists = true; break; }
         if(!exists && obCnt < 50)
         {
            ArrayResize(obZones, obCnt+1);
            obZones[obCnt].top = h; obZones[obCnt].bottom = l;
            obZones[obCnt].isBullish = false; obZones[obCnt].used = false;
            obZones[obCnt].time = iTime(_Symbol, PERIOD_M5, i);
            obCnt++;
         }
      }
   }
}

void DetectFVGs()
{
   int valid = 0;
   for(int i = 0; i < fvgCnt; i++)
      if(!fvgZones[i].used) { if(valid != i) fvgZones[valid] = fvgZones[i]; valid++; }
   fvgCnt = valid;

   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   for(int i = 2; i <= 6; i++)
   {
      double hp = iHigh(_Symbol, PERIOD_M5, i);
      double ln = iLow(_Symbol, PERIOD_M5, i-2);
      double hn = iHigh(_Symbol, PERIOD_M5, i-2);
      double lp = iLow(_Symbol, PERIOD_M5, i);

      if(ln > hp && (ln - hp)/point >= InpFVG_MinSize && fvgCnt < 50)
      {
         ArrayResize(fvgZones, fvgCnt+1);
         fvgZones[fvgCnt].top = ln; fvgZones[fvgCnt].bottom = hp;
         fvgZones[fvgCnt].isBullish = true; fvgZones[fvgCnt].used = false;
         fvgZones[fvgCnt].time = iTime(_Symbol, PERIOD_M5, i-1);
         fvgCnt++;
      }
      if(hn < lp && (lp - hn)/point >= InpFVG_MinSize && fvgCnt < 50)
      {
         ArrayResize(fvgZones, fvgCnt+1);
         fvgZones[fvgCnt].top = lp; fvgZones[fvgCnt].bottom = hn;
         fvgZones[fvgCnt].isBullish = false; fvgZones[fvgCnt].used = false;
         fvgZones[fvgCnt].time = iTime(_Symbol, PERIOD_M5, i-1);
         fvgCnt++;
      }
   }
}

//+------------------------------------------------------------------+
//| Check VWAP + SMC Entry                                            |
//+------------------------------------------------------------------+
void CheckVWAPEntry()
{
   if(vwap_value == 0 || vwapBarCount < 10) return;

   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

   // MODE 1: FADE at 2nd StdDev + OB/FVG confluence
   if(InpFadeMode)
   {
      // Price at upper 2nd band = potential SHORT (mean reversion)
      if(bid >= vwap_upper2)
      {
         // Look for bearish OB or FVG near this level
         for(int i = 0; i < obCnt; i++)
         {
            if(obZones[i].used || obZones[i].isBullish) continue;
            double dist = MathAbs(obZones[i].top - bid) / point;
            if(dist <= InpVWAP_ProxPips && bid >= obZones[i].bottom && bid <= obZones[i].top)
            {
               double sl = obZones[i].top + 10 * point;
               double slDist = sl - bid;
               double tp = vwap_value; // Target VWAP
               if((bid - tp) / slDist < 1.0) tp = bid - slDist * InpRR; // Min RR

               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Sell(lots, _Symbol, bid, sl, tp, InpComment+"_FadeUp"))
               {
                  obZones[i].used = true; dailyTrades++;
                  Print("SELL: VWAP Fade Upper + OB | VWAP:", vwap_value, " Upper2:", vwap_upper2);
                  return;
               }
            }
         }
         // Check FVGs too
         for(int i = 0; i < fvgCnt; i++)
         {
            if(fvgZones[i].used || fvgZones[i].isBullish) continue;
            if(bid >= fvgZones[i].bottom && bid <= fvgZones[i].top)
            {
               double sl = fvgZones[i].top + 10 * point;
               double slDist = sl - bid;
               double tp = vwap_value;
               if((bid - tp) / slDist < 1.0) tp = bid - slDist * InpRR;
               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Sell(lots, _Symbol, bid, sl, tp, InpComment+"_FadeUp_FVG"))
               {
                  fvgZones[i].used = true; dailyTrades++;
                  return;
               }
            }
         }
      }

      // Price at lower 2nd band = potential BUY
      if(ask <= vwap_lower2)
      {
         for(int i = 0; i < obCnt; i++)
         {
            if(obZones[i].used || !obZones[i].isBullish) continue;
            double dist = MathAbs(obZones[i].bottom - ask) / point;
            if(dist <= InpVWAP_ProxPips && ask >= obZones[i].bottom && ask <= obZones[i].top)
            {
               double sl = obZones[i].bottom - 10 * point;
               double slDist = ask - sl;
               double tp = vwap_value;
               if((tp - ask) / slDist < 1.0) tp = ask + slDist * InpRR;
               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Buy(lots, _Symbol, ask, sl, tp, InpComment+"_FadeDn"))
               {
                  obZones[i].used = true; dailyTrades++;
                  Print("BUY: VWAP Fade Lower + OB | VWAP:", vwap_value);
                  return;
               }
            }
         }
         for(int i = 0; i < fvgCnt; i++)
         {
            if(fvgZones[i].used || !fvgZones[i].isBullish) continue;
            if(ask >= fvgZones[i].bottom && ask <= fvgZones[i].top)
            {
               double sl = fvgZones[i].bottom - 10 * point;
               double slDist = ask - sl;
               double tp = vwap_value;
               if((tp - ask) / slDist < 1.0) tp = ask + slDist * InpRR;
               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Buy(lots, _Symbol, ask, sl, tp, InpComment+"_FadeDn_FVG"))
               {
                  fvgZones[i].used = true; dailyTrades++;
                  return;
               }
            }
         }
      }
   }

   // MODE 2: VWAP bounce + trend continuation
   if(InpTrendMode)
   {
      double close1 = iClose(_Symbol, PERIOD_M5, 1);
      double low1 = iLow(_Symbol, PERIOD_M5, 1);
      double high1 = iHigh(_Symbol, PERIOD_M5, 1);

      // Bullish: price above VWAP, bounced off VWAP (touched lower1)
      if(close1 > vwap_value && low1 <= vwap_upper1 && low1 >= vwap_lower1)
      {
         // Confirmation: bullish OB at VWAP level
         for(int i = 0; i < obCnt; i++)
         {
            if(obZones[i].used || !obZones[i].isBullish) continue;
            if(MathAbs(obZones[i].bottom - vwap_value)/point <= InpVWAP_ProxPips)
            {
               double sl = MathMin(obZones[i].bottom, vwap_lower1) - 5*point;
               double slDist = ask - sl;
               double tp = ask + slDist * InpRR;
               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Buy(lots, _Symbol, ask, sl, tp, InpComment+"_VBounce"))
               {
                  obZones[i].used = true; dailyTrades++;
                  Print("BUY: VWAP Bounce + OB confluence");
                  return;
               }
            }
         }
      }

      // Bearish: price below VWAP, bounced off VWAP
      if(close1 < vwap_value && high1 >= vwap_lower1 && high1 <= vwap_upper1)
      {
         for(int i = 0; i < obCnt; i++)
         {
            if(obZones[i].used || obZones[i].isBullish) continue;
            if(MathAbs(obZones[i].top - vwap_value)/point <= InpVWAP_ProxPips)
            {
               double sl = MathMax(obZones[i].top, vwap_upper1) + 5*point;
               double slDist = sl - bid;
               double tp = bid - slDist * InpRR;
               double lots = CalcLots(slDist);
               if(lots > 0 && trade.Sell(lots, _Symbol, bid, sl, tp, InpComment+"_VBounceS"))
               {
                  obZones[i].used = true; dailyTrades++;
                  Print("SELL: VWAP Bounce + OB confluence");
                  return;
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
// Utility
bool InSession()
{
   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   int etH = dt.hour - InpGMTOffset - 5; if(etH < 0) etH += 24;
   int cur = etH*60+dt.min;
   return (cur >= InpStartHour*60+InpStartMin && cur <= InpEndHour*60+InpEndMin);
}

double CalcLots(double slDist)
{
   if(slDist <= 0) return 0;
   double risk = AccountInfoDouble(ACCOUNT_BALANCE) * InpRiskPct / 100.0;
   double tv = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double ts = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(ts == 0 || tv == 0) return 0;
   double lots = risk / (slDist / ts * tv);
   double lMin = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lMax = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 20.0);
   double lStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   lots = MathFloor(lots / lStep) * lStep;
   return MathMax(MathMin(lots, lMax), lMin);
}

bool HasPos()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   { if(!posInfo.SelectByIndex(i)) continue;
     if(posInfo.Magic() == InpMagic && posInfo.Symbol() == _Symbol) return true; }
   return false;
}

void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request, const MqlTradeResult &result)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
   if(!HistoryDealSelect(trans.deal)) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_MAGIC) != InpMagic) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;

   double profit = HistoryDealGetDouble(trans.deal, DEAL_PROFIT) +
                   HistoryDealGetDouble(trans.deal, DEAL_COMMISSION) +
                   HistoryDealGetDouble(trans.deal, DEAL_SWAP);
   dailyPnL += profit; totalTrades++;
   if(profit >= 0) { wins++; consecLosses=0; } else { losses++; consecLosses++; }

   int idx = ArraySize(tradeLog);
   ArrayResize(tradeLog, idx+1);
   tradeLog[idx].ticket = (int)trans.deal;
   tradeLog[idx].closeTime = TimeCurrent();
   tradeLog[idx].pnl = profit;
   tradeLog[idx].lots = HistoryDealGetDouble(trans.deal, DEAL_VOLUME);
   tradeLog[idx].balAfter = AccountInfoDouble(ACCOUNT_BALANCE);
   tradeLog[idx].comment = HistoryDealGetString(trans.deal, DEAL_COMMENT);
   tradeLog[idx].entryType = StringFind(tradeLog[idx].comment, "Fade") >= 0 ? "Fade" : "Bounce";
}

void WriteReport()
{
   int h = FileOpen(InpCSVFile, FILE_WRITE|FILE_CSV|FILE_COMMON, ",");
   if(h == INVALID_HANDLE) return;

   double finalBal = AccountInfoDouble(ACCOUNT_BALANCE);
   double net = finalBal - initBal;
   double wr = totalTrades > 0 ? (double)wins/totalTrades*100 : 0;
   double gp = 0, gl = 0;
   int fadeWins=0, fadeLosses=0, bounceWins=0, bounceLosses=0;

   for(int i = 0; i < ArraySize(tradeLog); i++)
   {
      if(tradeLog[i].pnl > 0) { gp += tradeLog[i].pnl;
         if(tradeLog[i].entryType == "Fade") fadeWins++; else bounceWins++; }
      else { gl += MathAbs(tradeLog[i].pnl);
         if(tradeLog[i].entryType == "Fade") fadeLosses++; else bounceLosses++; }
   }

   FileWrite(h, "=== EA04: VWAP + SMC CONFLUENCE - BACKTEST REPORT ===");
   FileWrite(h, "Symbol", _Symbol); FileWrite(h, "Period", EnumToString(Period()));
   FileWrite(h, "Initial Balance", DoubleToString(initBal,2));
   FileWrite(h, "Final Balance", DoubleToString(finalBal,2));
   FileWrite(h, "");
   FileWrite(h, "=== SUMMARY ===");
   FileWrite(h, "Total Trades", IntegerToString(totalTrades));
   FileWrite(h, "Win Rate %", DoubleToString(wr,2));
   FileWrite(h, "Profit Factor", DoubleToString(gl>0?gp/gl:0,2));
   FileWrite(h, "Net Profit", DoubleToString(net,2));
   FileWrite(h, "Return %", DoubleToString(net/initBal*100,2));
   FileWrite(h, "Max DD %", DoubleToString(maxDD,2));
   FileWrite(h, "");
   FileWrite(h, "=== MODE BREAKDOWN ===");
   FileWrite(h, "Fade Wins/Losses", IntegerToString(fadeWins)+"/"+IntegerToString(fadeLosses));
   FileWrite(h, "Bounce Wins/Losses", IntegerToString(bounceWins)+"/"+IntegerToString(bounceLosses));
   FileWrite(h, "Fade WR%", DoubleToString((fadeWins+fadeLosses)>0?(double)fadeWins/(fadeWins+fadeLosses)*100:0,1));
   FileWrite(h, "Bounce WR%", DoubleToString((bounceWins+bounceLosses)>0?(double)bounceWins/(bounceWins+bounceLosses)*100:0,1));
   FileWrite(h, "");
   FileWrite(h, "=== PARAMETERS ===");
   FileWrite(h, "StdDev1", DoubleToString(InpVWAP_StdDev1,1));
   FileWrite(h, "StdDev2", DoubleToString(InpVWAP_StdDev2,1));
   FileWrite(h, "VWAP_ProxPips", IntegerToString((int)InpVWAP_ProxPips));
   FileWrite(h, "FadeMode", IntegerToString(InpFadeMode));
   FileWrite(h, "TrendMode", IntegerToString(InpTrendMode));
   FileWrite(h, "RR", DoubleToString(InpRR,1));
   FileWrite(h, "");
   FileWrite(h, "=== TRADES ===");
   FileWrite(h, "Ticket","Time","PnL","Lots","Balance","Type","Comment");
   for(int i = 0; i < ArraySize(tradeLog); i++)
      FileWrite(h, IntegerToString(tradeLog[i].ticket), TimeToString(tradeLog[i].closeTime),
                DoubleToString(tradeLog[i].pnl,2), DoubleToString(tradeLog[i].lots,2),
