//+------------------------------------------------------------------+
//| EA_05_ORB_Indices.mq5                                            |
//| Strategy: Opening Range Breakout (ORB)                           |
//| Assets: NAS100, US30, S&P500 - NY Open Scalping                 |
//| Author: Jose - Prop Firm Challenge EA Suite                       |
//+------------------------------------------------------------------+
#property copyright "Jose - Quant Trading"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Strategy
input group "=== STRATEGY ==="
input int      InpORB_Minutes       = 15;       // Opening Range duration (minutes after 9:30)
input double   InpBreakoutBuffer    = 5.0;      // Buffer beyond OR high/low (points)
input bool     InpUseVWAPFilter     = true;     // Filter: price side of VWAP
input bool     InpUseVolumeFilter   = true;     // Filter: volume > avg on breakout
input double   InpVolMultiplier     = 1.2;      // Volume must be X times avg
input int      InpMaxORB_Range      = 200;      // Max OR range (points) - skip wide ranges
input int      InpMinORB_Range      = 15;       // Min OR range (points) - skip flat ranges
input double   InpRangeProjection   = 1.5;      // TP = X times OR range from breakout
input bool     InpTrailAfter1R      = true;     // Trail stop after 1R profit

//--- Session (ORB specific - operates 9:30-12:00 ET)
input group "=== SESSION ==="
input int      InpMarketOpenHour    = 9;        // Market open hour ET
input int      InpMarketOpenMin     = 30;       // Market open minute ET
input int      InpCutoffHour        = 12;       // Stop taking trades hour ET
input int      InpCloseAllHour      = 15;       // Close all positions hour ET
input int      InpGMTOffset         = 2;        // Broker GMT offset

//--- Risk
input group "=== RISK ==="
input double   InpRiskPct           = 0.5;
input int      InpMaxDailyTrades    = 2;        // Usually 1-2 ORB trades per day
input double   InpDailyLossLim      = 4.0;
input double   InpMaxDDPct          = 8.0;
input int      InpMinDuration       = 90;

//--- Execution
input group "=== EXECUTION ==="
input int      InpMaxSpread         = 30;
input int      InpSlippage          = 10;
input int      InpMagic             = 100500;
input string   InpComment           = "ORB";

//--- Report
input group "=== REPORT ==="
input bool     InpCSV               = true;
input string   InpCSVFile           = "EA05_ORB_Indices_Report.csv";

CTrade trade;
CPositionInfo posInfo;

// ORB state
double   orbHigh, orbLow;
bool     orbCalculated;
bool     orbBreakoutDone;
datetime orbDate;
int      orbDirection; // 1=long breakout, -1=short breakout

// VWAP
double   vwapValue;
double   cumVP, cumV;
int      vwapBars;

struct TradeRec {
   int ticket; datetime closeTime; double pnl; double lots;
   double balAfter; string comment; double orbRange;
   int breakoutDir; double entryPrice;
};
TradeRec tradeLog[];

int totalTrades, wins, losses, dailyTrades, consecLosses;
double dailyPnL, initBal, peakBal, maxDD;
datetime lastDay;

// Stats
int longWins, longLosses, shortWins, shortLosses;
double avgORBRange;
int orbCount;

//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagic);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   initBal = AccountInfoDouble(ACCOUNT_BALANCE);
   peakBal = initBal; maxDD = 0;
   totalTrades = wins = losses = dailyTrades = consecLosses = 0;
   dailyPnL = 0; lastDay = 0;
   orbHigh = 0; orbLow = 0; orbCalculated = false; orbBreakoutDone = false;
   orbDate = 0; orbDirection = 0;
   vwapValue = 0; cumVP = 0; cumV = 0; vwapBars = 0;
   longWins = longLosses = shortWins = shortLosses = 0;
   avgORBRange = 0; orbCount = 0;
   ArrayResize(tradeLog, 0);
   Print("EA05 ORB Indices init. Bal: ", initBal);
   return INIT_SUCCEEDED;
}

void OnDeinit(const int reason)
{
   if(InpCSV && ArraySize(tradeLog) > 0) WriteReport();
}

//+------------------------------------------------------------------+
void OnTick()
{
   static datetime lastBar = 0;
   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   if(curBar == lastBar) return;
   lastBar = curBar;

   MqlDateTime dt; TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(IntegerToString(dt.year)+"."+IntegerToString(dt.mon)+"."+IntegerToString(dt.day));

   // Daily reset
   if(today != lastDay)
   {
      dailyTrades = 0; dailyPnL = 0; consecLosses = 0; lastDay = today;
      orbHigh = 0; orbLow = DBL_MAX; orbCalculated = false; orbBreakoutDone = false;
      orbDate = today; orbDirection = 0;
      cumVP = 0; cumV = 0; vwapBars = 0; vwapValue = 0;
   }

   // Drawdown
   double eq = AccountInfoDouble(ACCOUNT_EQUITY);
   if(eq > peakBal) peakBal = eq;
   double dd = (peakBal - eq) / initBal * 100.0;
   if(dd > maxDD) maxDD = dd;

   // Convert to ET
   int etH = dt.hour - InpGMTOffset - 5;
   if(etH < 0) etH += 24;
   int etM = dt.min;
   int etMinutes = etH * 60 + etM;
   int marketOpen = InpMarketOpenHour * 60 + InpMarketOpenMin; // 9:30 = 570
   int orbEnd = marketOpen + InpORB_Minutes;

   // Update VWAP after market open
   if(etMinutes >= marketOpen)
      UpdateVWAP();

   // Phase 1: Build Opening Range (9:30 - 9:30+ORB_Minutes)
   if(etMinutes >= marketOpen && etMinutes < orbEnd && !orbCalculated)
   {
      BuildOpeningRange(etMinutes, marketOpen);
      return;
   }

   // Mark ORB as calculated when time passes
   if(etMinutes >= orbEnd && !orbCalculated && orbHigh > 0 && orbLow < DBL_MAX)
   {
      orbCalculated = true;
      double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
      double range = (orbHigh - orbLow) / point;

      // Validate range
      if(range > InpMaxORB_Range || range < InpMinORB_Range)
      {
         orbBreakoutDone = true; // Skip today
         Print("ORB skipped: range=", range, " pts (limits: ", InpMinORB_Range, "-", InpMaxORB_Range, ")");
         return;
      }

      avgORBRange = (avgORBRange * orbCount + range) / (orbCount + 1);
      orbCount++;

      Print("ORB calculated: High=", orbHigh, " Low=", orbLow, " Range=", range, " pts");
   }

   // Risk checks
   if(dailyTrades >= InpMaxDailyTrades) goto manage;
   double bal = AccountInfoDouble(ACCOUNT_BALANCE);
   if(dailyPnL <= -(bal * InpDailyLossLim / 100.0)) goto manage;
   if(dd >= InpMaxDDPct) goto manage;

   // Phase 2: Watch for breakout (ORB_End - Cutoff)
   if(orbCalculated && !orbBreakoutDone && etMinutes < InpCutoffHour * 60)
   {
      if(SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) <= InpMaxSpread && !HasPos())
         CheckBreakout();
   }

   manage:
   // Phase 3: Manage positions (trailing, time exit)
   ManageORBPositions(etMinutes);
}

//+------------------------------------------------------------------+
void BuildOpeningRange(int etMinutes, int marketOpen)
{
   // Scan M5 bars within the opening range window
   for(int i = 0; i < 10; i++)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime bdt; TimeToStruct(barTime, bdt);
      int bET = bdt.hour - InpGMTOffset - 5;
      if(bET < 0) bET += 24;
      int bMin = bET * 60 + bdt.min;

      if(bMin >= marketOpen && bMin < marketOpen + InpORB_Minutes)
      {
         double h = iHigh(_Symbol, PERIOD_M5, i);
         double l = iLow(_Symbol, PERIOD_M5, i);
         if(h > orbHigh) orbHigh = h;
         if(l < orbLow) orbLow = l;
      }
   }
}

//+------------------------------------------------------------------+
void UpdateVWAP()
{
   double c = iClose(_Symbol, PERIOD_M5, 1);
   double h = iHigh(_Symbol, PERIOD_M5, 1);
   double l = iLow(_Symbol, PERIOD_M5, 1);
   long v = iVolume(_Symbol, PERIOD_M5, 1);
   if(v <= 0) v = 1;

   double tp = (h + l + c) / 3.0;
   cumVP += tp * (double)v;
   cumV += (double)v;
   vwapBars++;

   if(cumV > 0) vwapValue = cumVP / cumV;
}

//+------------------------------------------------------------------+
void CheckBreakout()
{
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double close1 = iClose(_Symbol, PERIOD_M5, 1);

   double breakHigh = orbHigh + InpBreakoutBuffer * point;
   double breakLow  = orbLow - InpBreakoutBuffer * point;
   double orbRange  = orbHigh - orbLow;

   // Volume filter
   if(InpUseVolumeFilter)
   {
      long vol1 = iVolume(_Symbol, PERIOD_M5, 1);
      long avgVol = 0;
      for(int i = 2; i < 22; i++) avgVol += iVolume(_Symbol, PERIOD_M5, i);
      avgVol /= 20;
      if(vol1 < (long)(avgVol * InpVolMultiplier)) return;
   }

   // === LONG BREAKOUT ===
   if(close1 > breakHigh)
   {
      // VWAP filter
      if(InpUseVWAPFilter && vwapValue > 0 && close1 < vwapValue) return;

      double sl = orbLow - InpBreakoutBuffer * point;
      double slDist = ask - sl;
      double tp = ask + orbRange * InpRangeProjection;

      double lots = CalcLots(slDist);
      if(lots <= 0) return;

      if(trade.Buy(lots, _Symbol, ask, sl, tp, InpComment+"_Long"))
      {
         orbBreakoutDone = true;
         orbDirection = 1;
         dailyTrades++;
         Print("ORB LONG: Entry=", ask, " SL=", sl, " TP=", tp, " Range=", orbRange/point, "pts");
      }
   }

   // === SHORT BREAKOUT ===
   if(close1 < breakLow)
   {
      if(InpUseVWAPFilter && vwapValue > 0 && close1 > vwapValue) return;

      double sl = orbHigh + InpBreakoutBuffer * point;
      double slDist = sl - bid;
      double tp = bid - orbRange * InpRangeProjection;

      double lots = CalcLots(slDist);
      if(lots <= 0) return;

      if(trade.Sell(lots, _Symbol, bid, sl, tp, InpComment+"_Short"))
      {
         orbBreakoutDone = true;
         orbDirection = -1;
         dailyTrades++;
         Print("ORB SHORT: Entry=", bid, " SL=", sl, " TP=", tp, " Range=", orbRange/point, "pts");
      }
   }
}

//+------------------------------------------------------------------+
void ManageORBPositions(int etMinutes)
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() != InpMagic || posInfo.Symbol() != _Symbol) continue;

      int duration = (int)(TimeCurrent() - posInfo.Time());

      // Time-based exit at close hour
      if(etMinutes >= InpCloseAllHour * 60 && duration >= InpMinDuration)
      {
         trade.PositionClose(posInfo.Ticket());
         Print("ORB: Time exit at ", InpCloseAllHour, ":00 ET");
         continue;
      }

      // Trailing stop after 1R
      if(InpTrailAfter1R && duration >= InpMinDuration)
      {
         double entry = posInfo.PriceOpen();
         double sl    = posInfo.StopLoss();
         double bid   = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         double ask   = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double point = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

         if(posInfo.PositionType() == POSITION_TYPE_BUY)
         {
            double risk = entry - sl;
            if(risk > 0 && bid > entry + risk) // Past 1R
            {
               double newSL = entry + risk * 0.5; // Trail to 0.5R
               if(newSL > sl)
                  trade.PositionModify(posInfo.Ticket(), newSL, posInfo.TakeProfit());
            }
         }
         else // SELL
         {
            double risk = sl - entry;
            if(risk > 0 && ask < entry - risk)
            {
               double newSL = entry - risk * 0.5;
               if(newSL < sl)
                  trade.PositionModify(posInfo.Ticket(), newSL, posInfo.TakeProfit());
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
double CalcLots(double slDist)
{
   if(slDist <= 0) return 0;
   double risk = AccountInfoDouble(ACCOUNT_BALANCE) * InpRiskPct / 100.0;
   double tv = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double ts = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   if(ts == 0 || tv == 0) return 0;
   double lots = risk / (slDist / ts * tv);
   double lMin = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double lMax = MathMin(SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX), 20.0);
   double lStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   lots = MathFloor(lots / lStep) * lStep;
   return MathMax(MathMin(lots, lMax), lMin);
}

bool HasPos()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   { if(!posInfo.SelectByIndex(i)) continue;
     if(posInfo.Magic() == InpMagic && posInfo.Symbol() == _Symbol) return true; }
   return false;
}

void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request, const MqlTradeResult &result)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
   if(!HistoryDealSelect(trans.deal)) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_MAGIC) != InpMagic) return;
   if(HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;

   double profit = HistoryDealGetDouble(trans.deal, DEAL_PROFIT) +
                   HistoryDealGetDouble(trans.deal, DEAL_COMMISSION) +
                   HistoryDealGetDouble(trans.deal, DEAL_SWAP);
   dailyPnL += profit; totalTrades++;

   bool isWin = (profit >= 0);
   if(isWin) { wins++; consecLosses=0; } else { losses++; consecLosses++; }

   if(orbDirection == 1) { if(isWin) longWins++; else longLosses++; }
   else if(orbDirection == -1) { if(isWin) shortWins++; else shortLosses++; }

   int idx = ArraySize(tradeLog);
   ArrayResize(tradeLog, idx+1);
   tradeLog[idx].ticket = (int)trans.deal;
   tradeLog[idx].closeTime = TimeCurrent();
   tradeLog[idx].pnl = profit;
   tradeLog[idx].lots = HistoryDealGetDouble(trans.deal, DEAL_VOLUME);
   tradeLog[idx].balAfter = AccountInfoDouble(ACCOUNT_BALANCE);
   tradeLog[idx].comment = HistoryDealGetString(trans.deal, DEAL_COMMENT);
   tradeLog[idx].orbRange = (orbHigh > 0 && orbLow < DBL_MAX) ? 
      (orbHigh - orbLow) / SymbolInfoDouble(_Symbol, SYMBOL_POINT) : 0;
   tradeLog[idx].breakoutDir = orbDirection;
   tradeLog[idx].entryPrice = HistoryDealGetDouble(trans.deal, DEAL_PRICE);
}

//+------------------------------------------------------------------+
void WriteReport()
{
   int h = FileOpen(InpCSVFile, FILE_WRITE|FILE_CSV|FILE_COMMON, ",");
   if(h == INVALID_HANDLE) return;

   double finalBal = AccountInfoDouble(ACCOUNT_BALANCE);
   double net = finalBal - initBal;
   double wr = totalTrades > 0 ? (double)wins/totalTrades*100 : 0;
   double gp = 0, gl = 0;
   for(int i = 0; i < ArraySize(tradeLog); i++)
   { if(tradeLog[i].pnl > 0) gp += tradeLog[i].pnl; else gl += MathAbs(tradeLog[i].pnl); }

   FileWrite(h, "=== EA05: OPENING RANGE BREAKOUT - BACKTEST REPORT ===");
   FileWrite(h, "Symbol", _Symbol); FileWrite(h, "Period", EnumToString(Period()));
   FileWrite(h, "Initial Balance", DoubleToString(initBal,2));
   FileWrite(h, "Final Balance", DoubleToString(finalBal,2));
   FileWrite(h, "");
   FileWrite(h, "=== SUMMARY ===");
   FileWrite(h, "Total Trades", IntegerToString(totalTrades));
   FileWrite(h, "Win Rate %", DoubleToString(wr,2));
   FileWrite(h, "Profit Factor", DoubleToString(gl>0?gp/gl:0,2));
   FileWrite(h, "Net Profit", DoubleToString(net,2));
   FileWrite(h, "Return %", DoubleToString(net/initBal*100,2));
   FileWrite(h, "Max DD %", DoubleToString(maxDD,2));
   FileWrite(h, "Expectancy", DoubleToString(totalTrades>0?net/totalTrades:0,2));
   FileWrite(h, "Avg ORB Range (pts)", DoubleToString(avgORBRange,1));
   FileWrite(h, "");

   FileWrite(h, "=== DIRECTIONAL BREAKDOWN ===");
   FileWrite(h, "Long Wins/Losses", IntegerToString(longWins)+"/"+IntegerToString(longLosses));
   FileWrite(h, "Short Wins/Losses", IntegerToString(shortWins)+"/"+IntegerToString(shortLosses));
   int longTotal = longWins+longLosses;
   int shortTotal = shortWins+shortLosses;
   FileWrite(h, "Long WR%", DoubleToString(longTotal>0?(double)longWins/longTotal*100:0,1));
   FileWrite(h, "Short WR%", DoubleToString(shortTotal>0?(double)shortWins/shortTotal*100:0,1));
   FileWrite(h, "");

   FileWrite(h, "=== PARAMETERS ===");
   FileWrite(h, "ORB_Minutes", IntegerToString(InpORB_Minutes));
   FileWrite(h, "BreakoutBuffer", DoubleToString(InpBreakoutBuffer,1));
   FileWrite(h, "VWAPFilter", IntegerToString(InpUseVWAPFilter));
   FileWrite(h, "VolumeFilter", IntegerToString(InpUseVolumeFilter));
   FileWrite(h, "VolMultiplier", DoubleToString(InpVolMultiplier,1));
   FileWrite(h, "MaxORBRange", IntegerToString(InpMaxORB_Range));
   FileWrite(h, "MinORBRange", IntegerToString(InpMinORB_Range));
   FileWrite(h, "RangeProjection", DoubleToString(InpRangeProjection,1));
   FileWrite(h, "TrailAfter1R", IntegerToString(InpTrailAfter1R));
   FileWrite(h, "");

   FileWrite(h, "=== TRADES ===");
   FileWrite(h, "Ticket","Time","PnL","Lots","Balance","Dir","ORBRange","Comment");
   for(int i = 0; i < ArraySize(tradeLog); i++)
      FileWrite(h, IntegerToString(tradeLog[i].ticket), TimeToString(tradeLog[i].closeTime),
                DoubleToString(tradeLog[i].pnl,2), DoubleToString(tradeLog[i].lots,2),
                DoubleToString(tradeLog[i].balAfter,2),
                tradeLog[i].breakoutDir==1?"LONG":"SHORT",
                DoubleToString(tradeLog[i].orbRange,0),
                tradeLog[i].comment);

   FileWrite(h, ""); FileWrite(h, "=== PROP CHECK ===");
   FileWrite(h, "Max DD < 10%", maxDD < 10 ? "PASS" : "FAIL");
   FileClose(h);
   Print("EA05 Report: ", InpCSVFile);
}
